const INDEX_HTML = "<!DOCTYPE html>\n<html lang=\"ja\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n<meta name=\"theme-color\" content=\"#7fffb2\">\n<link rel=\"manifest\" href=\"/manifest.json\">\n<title>YT Watcher</title>\n<style>\n:root{--bg:#0a0a0f;--bg2:#111118;--bg3:#1a1a24;--border:#2a2a38;--accent:#7fffb2;--accent2:#ff7f50;--accent3:#7fb8ff;--text:#e0e0e8;--muted:#666678;--danger:#ff4466;--r:6px;--bar:28px;--tab:34px}\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\nhtml,body{height:100%;background:var(--bg);color:var(--text);font-family:'Space Mono',monospace;font-size:13px;overflow:hidden}\n::-webkit-scrollbar{width:4px;height:4px}::-webkit-scrollbar-thumb{background:var(--border);border-radius:2px}\n#bar{position:fixed;top:0;left:0;right:0;height:var(--bar);background:rgba(10,10,15,.95);backdrop-filter:blur(12px);border-bottom:1px solid var(--border);display:flex;align-items:center;z-index:200}\n.dots{display:flex;gap:6px;padding:0 12px}.dot{width:11px;height:11px;border-radius:50%}\n.dot.r{background:#ff5f57}.dot.y{background:#ffbd2e}.dot.g{background:#28c840}\n.bar-title{padding:0 8px;font-weight:bold;color:var(--accent);font-size:12px}.spacer{flex:1}\n.bar-right{display:flex;align-items:center;gap:5px;padding:0 8px}\n.badge{font-size:10px;padding:1px 6px;border-radius:8px;background:var(--accent);color:#000;font-weight:bold;cursor:pointer;white-space:nowrap}\n.badge.off{background:var(--muted)}.badge.warn{background:var(--accent2)}\n.bar-btn{background:none;border:none;color:var(--muted);cursor:pointer;padding:3px 6px;font-size:11px;border-radius:4px;font-family:inherit}\n.bar-btn:hover{background:var(--bg3);color:var(--text)}\n#tabbar{position:fixed;top:var(--bar);left:0;right:0;height:var(--tab);background:var(--bg2);border-bottom:1px solid var(--border);display:flex;align-items:flex-end;padding:0 4px;overflow-x:auto;overflow-y:hidden;z-index:190;gap:1px}\n#tabbar::-webkit-scrollbar{height:2px}\n.tab-item{flex-shrink:0;height:28px;min-width:120px;max-width:200px;display:flex;align-items:center;gap:5px;padding:0 8px;background:var(--bg3);border:1px solid var(--border);border-bottom:none;border-radius:6px 6px 0 0;cursor:pointer;position:relative;user-select:none}\n.tab-item.active{background:var(--bg);border-bottom-color:var(--bg)}\n.tab-item.active::after{content:'';position:absolute;bottom:-1px;left:0;right:0;height:1px;background:var(--bg)}\n.tab-icon{width:13px;height:13px;flex-shrink:0;opacity:.5;fill:currentColor}.tab-item.active .tab-icon{opacity:1}\n.tab-name{flex:1;font-size:11px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:var(--muted)}.tab-item.active .tab-name{color:var(--text)}\n.tab-item.pinned{min-width:90px;max-width:120px}\n.tab-close{width:16px;height:16px;border-radius:50%;border:none;background:transparent;color:var(--muted);cursor:pointer;font-size:11px;flex-shrink:0;padding:0;display:flex;align-items:center;justify-content:center}\n.tab-close:hover{background:rgba(255,68,102,.2);color:var(--danger)}\n.tab-add{flex-shrink:0;width:28px;height:28px;border:none;background:transparent;color:var(--muted);cursor:pointer;font-size:18px;border-radius:6px 6px 0 0;display:flex;align-items:center;justify-content:center;margin-left:2px}\n.tab-add:hover{background:var(--bg3);color:var(--accent)}\n#app{position:fixed;top:62px;left:0;right:0;bottom:0;overflow:hidden}\n.pane{position:absolute;inset:0;overflow-y:auto;display:none;padding:12px}.pane.active{display:block}\ninput[type=text],input[type=date],input[type=time],input[type=url],textarea,select{background:var(--bg3);border:1px solid var(--border);border-radius:var(--r);color:var(--text);padding:7px 10px;font-family:inherit;font-size:12px;outline:none;width:100%}\ninput[type=color]{width:36px;height:30px;padding:2px;border:1px solid var(--border);border-radius:var(--r);background:var(--bg3);cursor:pointer}\ninput:focus,textarea:focus,select:focus{border-color:var(--accent)}\nselect option{background:var(--bg2)}\nbutton{padding:7px 14px;border-radius:var(--r);border:none;cursor:pointer;font-family:inherit;font-size:12px;transition:all .15s}\n.btn-accent{background:var(--accent);color:#000;font-weight:bold}.btn-accent:hover{filter:brightness(1.1)}\n.btn-outline{background:transparent;border:1px solid var(--border);color:var(--text)}.btn-outline:hover{border-color:var(--accent);color:var(--accent)}\n.btn-sm{padding:4px 10px;font-size:10px}\n.btn-danger{background:transparent;border:1px solid var(--danger);color:var(--danger)}.btn-danger:hover{background:var(--danger);color:#fff}\n.field{margin-bottom:10px}.field label{display:block;font-size:10px;color:var(--muted);margin-bottom:3px;text-transform:uppercase;letter-spacing:.06em}\n.errmsg{font-size:11px;color:var(--danger);margin-top:5px;display:none}\n.btn-row{display:flex;gap:8px;flex-wrap:wrap;margin-top:10px}\n.empty{text-align:center;padding:40px 20px;color:var(--muted);line-height:2;font-size:12px}\n.loading{text-align:center;padding:30px;color:var(--muted);font-size:12px}\n/* Playlist */\n.setup-box{max-width:480px;margin:30px auto;background:var(--bg2);border:1px solid var(--border);border-radius:var(--r);padding:20px}\n.setup-box h2{font-size:13px;color:var(--accent);margin-bottom:14px}\n.vid-header{display:flex;align-items:center;gap:8px;margin-bottom:10px;flex-wrap:wrap}\n.video-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:10px}\n.video-card{background:var(--bg2);border:1px solid var(--border);border-radius:var(--r);overflow:hidden;cursor:pointer;transition:border-color .15s}\n.video-card:hover{border-color:var(--accent)}\n.video-card img{width:100%;aspect-ratio:16/9;object-fit:cover;display:block;background:var(--bg3)}\n.vc-title{padding:8px;font-size:11px;line-height:1.4;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}\n/* Schedule top */\n.sched-top{background:var(--bg2);border:1px solid var(--border);border-radius:var(--r);padding:10px;margin-bottom:10px}\n.sched-top-row{display:flex;align-items:center;gap:6px;flex-wrap:wrap}\n.sched-top-row h2{font-size:12px;color:var(--accent3);flex:1;display:flex;align-items:center;gap:5px}\n#sched-json{height:80px;resize:vertical;font-size:11px;margin-top:8px;display:none}\n#sched-json.open{display:block}\n/* Selection */\n#sel-toolbar{background:var(--bg3);border:1px solid var(--accent3);border-radius:var(--r);padding:7px 10px;margin-bottom:8px;display:none;align-items:center;gap:6px;flex-wrap:wrap}\n#sel-toolbar.show{display:flex}\n.sel-count{font-size:12px;color:var(--accent3);flex:1}\n.sel-btn{display:flex;align-items:center;gap:4px;padding:3px 9px;border-radius:var(--r);border:1px solid var(--border);cursor:pointer;font-size:11px;font-family:inherit;background:var(--bg2);color:var(--text)}\n.sel-btn:hover{border-color:var(--accent);color:var(--accent)}\n.sel-btn.danger{border-color:var(--danger);color:var(--danger)}.sel-btn.danger:hover{background:var(--danger);color:#fff}\n.sel-btn svg{width:11px;height:11px;fill:currentColor;flex-shrink:0}\n#mobile-sel-banner{display:none;background:rgba(127,184,255,.08);border:1px solid rgba(127,184,255,.25);border-radius:var(--r);padding:6px 10px;margin-bottom:8px;font-size:11px;color:var(--accent3);align-items:center;gap:6px}\n#mobile-sel-banner.show{display:flex}\n/* Calendar */\n#cal-wrap{display:none}#cal-wrap.show{display:block}\n.cal-nav{display:flex;align-items:center;gap:8px;margin-bottom:8px}\n.cal-nav h3{flex:1;text-align:center;font-size:13px}\n.cal-filter-row{display:flex;gap:6px;margin-bottom:8px;flex-wrap:wrap}\n.cal-filter-btn{padding:3px 10px;border-radius:999px;border:1px solid var(--border);font-size:10px;cursor:pointer;background:transparent;color:var(--muted);font-family:inherit}\n.cal-filter-btn.active{background:var(--accent3);border-color:var(--accent3);color:#000;font-weight:bold}\n.cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:2px}\n.cal-head{text-align:center;font-size:10px;color:var(--muted);padding:3px 0}\n.cal-day{min-height:48px;background:var(--bg2);border:1px solid var(--border);border-radius:4px;padding:4px;cursor:pointer}\n.cal-day:hover{border-color:var(--accent)}.cal-day.today{border-color:var(--accent)}\n.cal-day.other-month .cal-dn{opacity:.35}.cal-day.selected{border-color:var(--accent3);background:rgba(127,184,255,.06)}\n.cal-dn{font-size:11px;font-weight:bold;margin-bottom:3px}\n.cal-dots{display:flex;flex-wrap:wrap;gap:2px}\n.cal-dot{width:6px;height:6px;border-radius:50%}\n.cal-events-box{background:var(--bg2);border:1px solid var(--border);border-radius:var(--r);padding:10px;margin-top:8px}\n.cal-events-box h4{font-size:11px;color:var(--accent3);margin-bottom:8px;display:flex;align-items:center;gap:6px}\n.cal-ev{border-radius:0 var(--r) var(--r) 0;padding:8px 10px;margin-bottom:6px;border-left:3px solid var(--accent3)}\n.cal-ev-sub{font-weight:bold;display:flex;align-items:center;justify-content:space-between;gap:6px}\n.cal-ev-meta{color:var(--muted);font-size:10px;margin-top:2px}\n.cal-ev-actions{display:flex;gap:5px;margin-top:6px;flex-wrap:wrap;align-items:center}\n/* Cards */\n.sched-group{margin-bottom:10px}\n.sched-group-header{display:flex;align-items:center;gap:8px;padding:5px 8px;border-radius:var(--r);margin-bottom:5px;cursor:pointer;background:var(--bg3)}\n.sched-group-header:hover{filter:brightness(1.05)}\n.sgh-dot{width:10px;height:10px;border-radius:50%;flex-shrink:0}\n.sgh-name{font-size:12px;font-weight:bold;flex:1}\n.sgh-count{font-size:10px;color:var(--muted)}\n.sgh-toggle{font-size:10px;color:var(--muted);margin-left:auto}\n.group-events{display:flex;flex-direction:column;gap:5px;overflow:hidden}\n.group-events.collapsed .s-card:nth-child(n+2){display:none}\n.sched-cards{display:flex;flex-direction:column;gap:7px}\n.s-card{background:var(--bg2);border:1px solid var(--border);border-radius:9px;display:flex;overflow:hidden;transition:border-color .15s,opacity .2s,filter .2s}\n.s-card.selected{border-color:var(--accent3);background:rgba(127,184,255,.05)}\n.s-card.notify-on{border-left:3px solid var(--accent3)}\n.s-card.notify-bright{filter:brightness(1.15)}\n.s-card.completed{opacity:.3;filter:grayscale(.6)}\n.s-card.dim-duplicate{opacity:.45;filter:grayscale(.3)}\n.s-cb-col{display:flex;align-items:flex-start;padding:12px 3px 12px 9px;flex-shrink:0;cursor:pointer}\n.s-checkbox{width:15px;height:15px;border:1.5px solid var(--border);border-radius:4px;display:flex;align-items:center;justify-content:center;transition:all .15s}\n.s-card.selected .s-checkbox{background:var(--accent3);border-color:var(--accent3)}\n.s-checkbox svg{width:9px;height:9px;fill:#000;display:none}.s-card.selected .s-checkbox svg{display:block}\n.s-body{flex:1;padding:10px 10px 10px 4px;display:flex;flex-direction:column;gap:7px;min-width:0}\n.s-head{display:flex;justify-content:space-between;align-items:flex-start;gap:6px}\n.s-subject{font-size:15px;font-weight:bold}.s-unit{font-size:11px;color:var(--muted);margin-top:2px}\n.s-date{font-size:11px;color:var(--muted);display:flex;align-items:center;gap:4px}\n.s-time{font-size:11px;display:flex;align-items:center;gap:4px}\n.s-def{font-size:10px;color:var(--muted)}\n.s-badges{display:flex;gap:5px;flex-wrap:wrap;align-items:center}\n.s-rel{padding:2px 8px;border-radius:999px;font-size:10px;font-weight:bold}\n.s-rel.future{background:rgba(127,184,255,.12);color:var(--accent3);border:1px solid rgba(127,184,255,.2)}\n.s-rel.today{background:rgba(127,255,178,.1);color:var(--accent);border:1px solid rgba(127,255,178,.2)}\n.s-rel.past{background:rgba(255,68,102,.08);color:var(--danger);border:1px solid rgba(255,68,102,.15)}\n.s-status{padding:2px 8px;border-radius:999px;font-size:10px}\n.s-status.normal{background:rgba(127,184,255,.1);color:var(--accent3)}\n.s-status.h_class{background:rgba(255,200,50,.1);color:#ffcc33}\n.s-status.s_class{background:rgba(255,68,102,.1);color:var(--danger)}\n.tog-wrap{display:flex;align-items:center;gap:5px;font-size:11px;color:var(--muted);cursor:pointer}\n.tog{position:relative;width:36px;height:19px;display:inline-block;flex-shrink:0}\n.tog input{display:none}.tog-sl{position:absolute;inset:0;background:var(--border);border-radius:999px;transition:.2s}\n.tog-sl:before{content:'';position:absolute;width:13px;height:13px;left:3px;top:3px;background:#fff;border-radius:50%;transition:.2s}\n.tog input:checked+.tog-sl{background:var(--accent3)}.tog input:checked+.tog-sl:before{transform:translateX(17px)}\n.tog.done input:checked+.tog-sl{background:var(--accent)}\n.s-link-btn{padding:3px 9px;border-radius:var(--r);background:rgba(16,185,129,.1);border:1px solid rgba(16,185,129,.2);color:#10b981;cursor:pointer;font-size:10px;font-family:inherit;display:flex;align-items:center;gap:3px}\n.s-link-btn:hover{background:rgba(16,185,129,.2)}\n.s-link-btn svg{width:10px;height:10px;fill:currentColor}\n.s-divider{text-align:center;font-size:10px;color:var(--muted);padding:5px 0;border-top:1px solid var(--border);margin:3px 0}\n/* Panels */\n#notif-panel,#recent-panel{position:fixed;top:var(--bar);width:280px;bottom:0;background:var(--bg2);z-index:180;display:flex;flex-direction:column;transition:transform .25s}\n#notif-panel{right:0;border-left:1px solid var(--border);transform:translateX(100%)}\n#notif-panel.open{transform:translateX(0)}\n#recent-panel{left:0;border-right:1px solid var(--border);transform:translateX(-100%)}\n#recent-panel.open{transform:translateX(0)}\n.panel-header{padding:10px 14px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between;font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.08em}\n.panel-list{flex:1;overflow-y:auto;padding:8px}\n.notif-item{background:var(--bg3);border:1px solid var(--border);border-radius:var(--r);padding:10px;margin-bottom:6px}\n.ni-title{font-weight:bold;color:var(--accent);font-size:11px;margin-bottom:2px}\n.ni-body{font-size:11px;color:var(--text);line-height:1.5}\n.ni-time{font-size:10px;color:var(--muted);margin-top:3px}\n.ni-link{display:inline-block;font-size:10px;color:var(--accent3);text-decoration:none;margin-top:3px}\n.recent-item{background:var(--bg3);border:1px solid var(--border);border-radius:var(--r);padding:10px;margin-bottom:6px;display:flex;align-items:center;gap:8px}\n.ri-info{flex:1;min-width:0}.ri-name{font-size:12px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}\n.ri-pl{font-size:10px;color:var(--muted)}.ri-time{font-size:10px;color:var(--muted);margin-top:2px}\n/* Modals */\n.modal-bg{display:none;position:fixed;inset:0;background:rgba(0,0,0,.65);z-index:300;align-items:center;justify-content:center;padding:16px}\n.modal-bg.open{display:flex}\n.modal-box{background:var(--bg2);border:1px solid var(--border);border-radius:10px;padding:20px;width:420px;max-width:100%;max-height:90vh;overflow-y:auto}\n.modal-box h3{font-size:12px;color:var(--accent);margin-bottom:12px}\n.share-url{background:var(--bg3);border:1px solid var(--border);border-radius:var(--r);padding:8px 10px;font-size:11px;color:var(--accent);word-break:break-all;margin-bottom:8px;line-height:1.6;font-family:monospace;cursor:pointer}\n.share-url:hover{border-color:var(--accent)}\n.sec{font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;margin-bottom:6px}\n.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px}\n/* Color swatch row */\n.color-row{display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin-top:4px}\n.color-swatch{width:22px;height:22px;border-radius:50%;cursor:pointer;border:2px solid transparent;transition:transform .1s}\n.color-swatch:hover{transform:scale(1.15)}.color-swatch.active{border-color:#fff}\n</style>\n<link href=\"https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&display=swap\" rel=\"stylesheet\">\n</head>\n<body>\n<div id=\"bar\">\n  <div class=\"dots\"><div class=\"dot r\"></div><div class=\"dot y\"></div><div class=\"dot g\"></div></div>\n  <span class=\"bar-title\">YT Watcher</span>\n  <div class=\"spacer\"></div>\n  <div class=\"bar-right\">\n    <button class=\"bar-btn\" onclick=\"toggleRecent()\">\u6700\u8fd1</button>\n    <button class=\"bar-btn\" onclick=\"openShare()\">\u5171\u6709</button>\n    <span class=\"badge off\" id=\"push-badge\" onclick=\"togglePush()\">PUSH OFF</span>\n    <span class=\"badge off\" id=\"notif-badge\" onclick=\"toggleNotifPanel()\">0\u4ef6</span>\n  </div>\n</div>\n\n<div id=\"tabbar\">\n  <div class=\"tab-item pinned\" id=\"online-tab\" onclick=\"switchToOnline()\">\n    <svg class=\"tab-icon\" viewBox=\"0 0 24 24\"><path d=\"M19 4h-1V2h-2v2H8V2H6v2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 16H5V9h14v11zM7 11h5v5H7z\"/></svg>\n    <span class=\"tab-name\">\u30aa\u30f3\u30e9\u30a4\u30f3</span>\n  </div>\n  <button class=\"tab-add\" onclick=\"addTab()\">+</button>\n</div>\n\n<div id=\"app\">\n  <div class=\"pane\" id=\"pane-online\">\n    <div class=\"sched-top\">\n      <div class=\"sched-top-row\">\n        <h2><svg width=\"13\" height=\"13\" viewBox=\"0 0 24 24\" fill=\"var(--accent3)\"><path d=\"M19 4h-1V2h-2v2H8V2H6v2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 16H5V9h14v11zM7 11h5v5H7z\"/></svg>\u30aa\u30f3\u30e9\u30a4\u30f3\u901a\u77e5</h2>\n        <button class=\"btn-outline btn-sm\" onclick=\"openAddEvent()\">\uff0b \u8ffd\u52a0</button>\n        <button class=\"btn-outline btn-sm\" onclick=\"toggleJsonArea()\">JSON\u8aad\u8fbc</button>\n        <button class=\"btn-outline btn-sm\" id=\"view-btn\" onclick=\"toggleView()\">\u30ab\u30ec\u30f3\u30c0\u30fc</button>\n        <button class=\"btn-outline btn-sm\" onclick=\"openSchedShare()\">\u5171\u6709</button>\n        <button class=\"btn-danger btn-sm\" onclick=\"clearSchedule()\">\u5168\u524a\u9664</button>\n      </div>\n      <textarea id=\"sched-json\" placeholder='{\"schedule\":[...]} \u307e\u305f\u306f schedule\u914d\u5217'></textarea>\n      <div id=\"sched-err\" class=\"errmsg\"></div>\n      <div id=\"sched-load-row\" style=\"display:none;margin-top:6px\" class=\"btn-row\">\n        <button class=\"btn-accent btn-sm\" onclick=\"loadScheduleJson()\">\u8aad\u307f\u8fbc\u3080</button>\n        <button class=\"btn-outline btn-sm\" onclick=\"toggleJsonArea()\">\u30ad\u30e3\u30f3\u30bb\u30eb</button>\n      </div>\n    </div>\n    <div id=\"mobile-sel-banner\">\n      <svg width=\"12\" height=\"12\" viewBox=\"0 0 24 24\" fill=\"currentColor\"><path d=\"M19 3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm-9 14l-5-5 1.41-1.41L10 14.17l7.59-7.59L19 8l-9 9z\"/></svg>\n      <span id=\"mb-sel-txt\">\u9078\u629e\u30e2\u30fc\u30c9</span><div style=\"flex:1\"></div>\n      <button class=\"sel-btn danger\" id=\"mb-del-btn\" style=\"display:none\" onclick=\"showDeleteConfirm()\"><svg viewBox=\"0 0 24 24\"><path d=\"M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z\"/></svg>\u524a\u9664</button>\n      <button class=\"sel-btn\" onclick=\"exitSelectionMode()\"><svg viewBox=\"0 0 24 24\"><path d=\"M19 6.41L17.59 5 12 10.59 6.41 5 5 6.41 10.59 12 5 17.59 6.41 19 12 13.41 17.59 19 19 17.59 13.41 12z\"/></svg>\u7d42\u4e86</button>\n    </div>\n    <div id=\"sel-toolbar\">\n      <span class=\"sel-count\" id=\"sel-count-text\">0\u4ef6\u9078\u629e</span>\n      <button class=\"sel-btn\" onclick=\"selectAll()\"><svg viewBox=\"0 0 24 24\"><path d=\"M19 3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm-9 14l-5-5 1.41-1.41L10 14.17l7.59-7.59L19 8l-9 9z\"/></svg>\u5168\u9078\u629e</button>\n      <button class=\"sel-btn danger\" onclick=\"showDeleteConfirm()\"><svg viewBox=\"0 0 24 24\"><path d=\"M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z\"/></svg>\u524a\u9664</button>\n      <button class=\"sel-btn\" onclick=\"clearSelection()\"><svg viewBox=\"0 0 24 24\"><path d=\"M19 6.41L17.59 5 12 10.59 6.41 5 5 6.41 10.59 12 5 17.59 6.41 19 12 13.41 17.59 19 19 17.59 13.41 12z\"/></svg>\u89e3\u9664</button>\n    </div>\n    <div id=\"cal-wrap\">\n      <div class=\"cal-nav\">\n        <button class=\"btn-outline btn-sm\" onclick=\"calMove(-1)\">&#8249;</button>\n        <h3 id=\"cal-title\"></h3>\n        <button class=\"btn-outline btn-sm\" onclick=\"calMove(1)\">&#8250;</button>\n      </div>\n      <div class=\"cal-filter-row\">\n        <button class=\"cal-filter-btn active\" id=\"filt-all\" onclick=\"setCalFilter('all')\">\u5168\u3066</button>\n        <button class=\"cal-filter-btn\" id=\"filt-notify\" onclick=\"setCalFilter('notify')\">\u901a\u77e5ON\u306e\u307f</button>\n        <button class=\"cal-filter-btn\" id=\"filt-future\" onclick=\"setCalFilter('future')\">\u672a\u6765\u306e\u307f</button>\n      </div>\n      <div class=\"cal-grid\" id=\"cal-grid\"></div>\n      <div id=\"cal-events\" style=\"display:none\"></div>\n    </div>\n    <div id=\"list-wrap\">\n      <div id=\"sched-cards\"><div class=\"empty\">\u300c\uff0b \u8ffd\u52a0\u300d\u307e\u305f\u306fJSON\u3092\u8aad\u307f\u8fbc\u3093\u3067\u304f\u3060\u3055\u3044</div></div>\n    </div>\n  </div>\n</div>\n\n<!-- Panels -->\n<div id=\"notif-panel\">\n  <div class=\"panel-header\"><span>\u901a\u77e5\u30bb\u30f3\u30bf\u30fc</span><button class=\"btn-outline btn-sm\" onclick=\"clearNotifs()\">\u5168\u6d88\u53bb</button></div>\n  <div class=\"panel-list\" id=\"np-list\">\n    <div style=\"padding:8px\">\n      <button class=\"btn-outline btn-sm\" onclick=\"testLocalNotif()\" style=\"width:100%;margin-bottom:6px\">\u901a\u77e5\u30c6\u30b9\u30c8(\u30ed\u30fc\u30ab\u30eb)</button>\n      <button class=\"btn-accent btn-sm\" onclick=\"runServerCheck()\" style=\"width:100%;margin-bottom:6px\">\u30b5\u30fc\u30d0\u30fc\u30c1\u30a7\u30c3\u30af\u5b9f\u884c</button>\n      <div id=\"server-check-result\" style=\"font-size:10px;color:var(--muted);line-height:1.6;margin-bottom:6px\"></div>\n      <div id=\"push-debug\" style=\"font-size:10px;color:var(--muted);line-height:1.6;word-break:break-all\"></div>\n    </div>\n  </div>\n</div>\n<div id=\"recent-panel\">\n  <div class=\"panel-header\"><span>\u6700\u8fd1\u524a\u9664\u3057\u305f\u30bf\u30d6</span></div>\n  <div class=\"panel-list\" id=\"rp-list\"></div>\n</div>\n\n<!-- Modals -->\n<div class=\"modal-bg\" id=\"rename-modal\">\n  <div class=\"modal-box\"><h3>\u30bf\u30d6\u540d\u3092\u5909\u66f4</h3>\n    <div class=\"field\"><input type=\"text\" id=\"rename-input\" placeholder=\"\u30bf\u30d6\u540d\"></div>\n    <div class=\"btn-row\"><button class=\"btn-accent\" onclick=\"confirmRename()\">\u4fdd\u5b58</button><button class=\"btn-outline\" onclick=\"closeModal('rename-modal')\">\u30ad\u30e3\u30f3\u30bb\u30eb</button></div>\n  </div>\n</div>\n\n<!-- Playlist share -->\n<div class=\"modal-bg\" id=\"share-modal\">\n  <div class=\"modal-box\"><h3>\u30d7\u30ec\u30a4\u30ea\u30b9\u30c8\u3092\u5171\u6709</h3>\n    <div class=\"sec\">\u5171\u6709\u3059\u308b\u30bf\u30d6\u3092\u9078\u629e</div>\n    <div id=\"share-checks\" style=\"margin-bottom:12px\"></div>\n    <div id=\"share-result\" style=\"display:none\">\n      <div class=\"sec\">\u5171\u6709\u30ea\u30f3\u30af\uff08\u30bf\u30c3\u30d7\u3067\u30b3\u30d4\u30fc\uff09</div>\n      <div class=\"share-url\" id=\"share-url-text\" onclick=\"copyShareUrl()\"></div>\n      <div class=\"btn-row\" style=\"margin-bottom:8px\">\n        <button class=\"btn-accent btn-sm\" onclick=\"copyShareUrl()\">URL\u3092\u30b3\u30d4\u30fc</button>\n        <button class=\"btn-outline btn-sm\" onclick=\"copyShareJson()\">JSON\u3092\u30b3\u30d4\u30fc</button>\n      </div>\n    </div>\n    <div id=\"share-loading\" style=\"display:none;font-size:11px;color:var(--muted);margin-bottom:8px\">\u751f\u6210\u4e2d...</div>\n    <div class=\"btn-row\"><button class=\"btn-accent\" onclick=\"generateShareUrl()\">\u30ea\u30f3\u30af\u3092\u751f\u6210</button><button class=\"btn-outline\" onclick=\"closeModal('share-modal')\">\u9589\u3058\u308b</button></div>\n  </div>\n</div>\n\n<!-- Schedule share -->\n<div class=\"modal-bg\" id=\"sched-share-modal\">\n  <div class=\"modal-box\"><h3>\u4e88\u5b9a\u3092\u5171\u6709</h3>\n    <div class=\"sec\">\u5171\u6709\u3059\u308b\u4e88\u5b9a\u3092\u9078\u629e</div>\n    <div style=\"margin-bottom:8px;display:flex;gap:6px\">\n      <button class=\"btn-outline btn-sm\" onclick=\"schedShareSelectAll()\">\u5168\u9078\u629e</button>\n      <button class=\"btn-outline btn-sm\" onclick=\"schedShareSelectNone()\">\u5168\u89e3\u9664</button>\n    </div>\n    <div id=\"sched-share-checks\" style=\"margin-bottom:12px;max-height:200px;overflow-y:auto\"></div>\n    <div id=\"sched-share-result\" style=\"display:none\">\n      <div class=\"sec\">\u5171\u6709\u30ea\u30f3\u30af\uff08\u30bf\u30c3\u30d7\u3067\u30b3\u30d4\u30fc\uff09</div>\n      <div class=\"share-url\" id=\"sched-share-url\" onclick=\"copySchedShareUrl()\"></div>\n      <div class=\"btn-row\" style=\"margin-bottom:8px\">\n        <button class=\"btn-accent btn-sm\" onclick=\"copySchedShareUrl()\">URL\u3092\u30b3\u30d4\u30fc</button>\n        <button class=\"btn-outline btn-sm\" onclick=\"copySchedShareJson()\">JSON\u3092\u30b3\u30d4\u30fc</button>\n      </div>\n    </div>\n    <div id=\"sched-share-loading\" style=\"display:none;font-size:11px;color:var(--muted);margin-bottom:8px\">\u751f\u6210\u4e2d...</div>\n    <div class=\"btn-row\"><button class=\"btn-accent\" onclick=\"generateSchedShareUrl()\">\u30ea\u30f3\u30af\u3092\u751f\u6210</button><button class=\"btn-outline\" onclick=\"closeModal('sched-share-modal')\">\u9589\u3058\u308b</button></div>\n  </div>\n</div>\n\n<!-- Import modal -->\n<div class=\"modal-bg\" id=\"import-modal\">\n  <div class=\"modal-box\">\n    <h3 id=\"import-title\">\u30a4\u30f3\u30dd\u30fc\u30c8</h3>\n    <div class=\"sec\">\u30a4\u30f3\u30dd\u30fc\u30c8\u3059\u308b\u3082\u306e\u3092\u9078\u629e</div>\n    <div id=\"import-checks\" style=\"margin-bottom:12px;max-height:260px;overflow-y:auto\"></div>\n    <div class=\"btn-row\">\n      <button class=\"btn-accent\" onclick=\"confirmImport()\">\u30a4\u30f3\u30dd\u30fc\u30c8</button>\n      <button class=\"btn-outline\" onclick=\"closeModal('import-modal')\">\u30ad\u30e3\u30f3\u30bb\u30eb</button>\n    </div>\n  </div>\n</div>\n\n<div class=\"modal-bg\" id=\"delete-modal\">\n  <div class=\"modal-box\"><h3>\u4e88\u5b9a\u3092\u524a\u9664</h3>\n    <p style=\"font-size:12px;margin-bottom:14px\" id=\"delete-msg\"></p>\n    <div class=\"btn-row\"><button class=\"btn-danger\" onclick=\"confirmDelete()\">\u524a\u9664\u3059\u308b</button><button class=\"btn-outline\" onclick=\"closeModal('delete-modal')\">\u30ad\u30e3\u30f3\u30bb\u30eb</button></div>\n  </div>\n</div>\n\n<!-- Add/Edit event -->\n<div class=\"modal-bg\" id=\"event-modal\">\n  <div class=\"modal-box\">\n    <h3 id=\"event-modal-title\">\u4e88\u5b9a\u3092\u8ffd\u52a0</h3>\n    <div class=\"form-grid\">\n      <div class=\"field\"><label>\u6559\u79d1</label><input type=\"text\" id=\"ev-subject\" placeholder=\"\u7406\u79d1\" oninput=\"onSubjectInput()\"></div>\n      <div class=\"field\"><label>\u5358\u5143</label><input type=\"text\" id=\"ev-unit\" placeholder=\"\u907a\u4f1d\"></div>\n      <div class=\"field\"><label>\u65e5\u4ed8</label><input type=\"date\" id=\"ev-date\"></div>\n      <div class=\"field\"><label>\u9650</label>\n        <select id=\"ev-period\" onchange=\"onPeriodChange()\">\n          <option value=\"1\">1\u9650 (19:30\u301c)</option>\n          <option value=\"2\">2\u9650 (20:40\u301c)</option>\n          <option value=\"0\">\u30ab\u30b9\u30bf\u30e0</option>\n        </select>\n      </div>\n      <div class=\"field\"><label>\u958b\u59cb\u6642\u523b</label><input type=\"time\" id=\"ev-start\" value=\"19:30\"></div>\n      <div class=\"field\"><label>\u7d42\u4e86\u6642\u523b</label><input type=\"time\" id=\"ev-end\" value=\"21:00\"></div>\n      <div class=\"field\"><label>\u30b9\u30c6\u30fc\u30bf\u30b9</label>\n        <select id=\"ev-status\">\n          <option value=\"normal\">\u3007 \u901a\u5e38\u6388\u696d</option>\n          <option value=\"h_class\">H H\u30af\u30e9\u30b9</option>\n          <option value=\"s_class\">S S\u30af\u30e9\u30b9</option>\n        </select>\n      </div>\n      <div class=\"field\"><label>\u901a\u77e5 (\u5206\u524d)</label><input type=\"text\" id=\"ev-notify\" value=\"60,30,10\"></div>\n    </div>\n    <div class=\"field\"><label>Zoom/\u53c2\u52a0URL</label><input type=\"url\" id=\"ev-link\" placeholder=\"https://zoom.us/j/...\"></div>\n    <div class=\"field\"><label>\u30e1\u30e2</label><input type=\"text\" id=\"ev-memo\" placeholder=\"\u63d0\u51fa\u7269\u306a\u3069\"></div>\n    <div class=\"field\">\n      <label>\u8272\uff08\u6559\u79d1\u8272 / \u30a4\u30d9\u30f3\u30c8\u500b\u5225\u8272\uff09</label>\n      <div style=\"display:flex;gap:8px;align-items:center;margin-top:4px\">\n        <input type=\"color\" id=\"ev-color\" value=\"#7fb8ff\">\n        <div class=\"color-row\" id=\"palette-row\"></div>\n        <button class=\"btn-outline btn-sm\" onclick=\"saveSubjectColor()\">\u6559\u79d1\u306b\u9069\u7528</button>\n        <button class=\"btn-outline btn-sm\" onclick=\"clearEventColor()\">\u30ea\u30bb\u30c3\u30c8</button>\n      </div>\n    </div>\n    <div id=\"ev-err\" class=\"errmsg\"></div>\n    <div class=\"btn-row\">\n      <button class=\"btn-accent\" onclick=\"submitEvent()\">\u4fdd\u5b58</button>\n      <button class=\"btn-outline\" onclick=\"closeModal('event-modal')\">\u30ad\u30e3\u30f3\u30bb\u30eb</button>\n    </div>\n  </div>\n</div>\n\n<script>\nconst WORKER = window.__CFG?.worker || location.origin;\nconst VAPID  = window.__CFG?.vapid  || '';\nconst ONLINE = 'online';\nconst isMobile = () => window.matchMedia('(pointer:coarse)').matches;\n\n// \u2500\u2500 Color system \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconst PALETTE = [\n  '#7fffb2','#7fb8ff','#ff7f50','#ffcc33',\n  '#c77fff','#ff7fb0','#7fffd4','#ffa07a',\n  '#87ceeb','#98fb98','#dda0dd','#f08080',\n];\nlet subjectColors = JSON.parse(localStorage.getItem('yt_subject_colors') || '{}');\n\nfunction saveSubjectColors() { localStorage.setItem('yt_subject_colors', JSON.stringify(subjectColors)); }\n\nfunction autoColor(subject) {\n  if (!subject) return PALETTE[0];\n  let h = 0;\n  for (let i = 0; i < subject.length; i++) { h = (h << 5) - h + subject.charCodeAt(i); h |= 0; }\n  return PALETTE[Math.abs(h) % PALETTE.length];\n}\n\nfunction getEventColor(ev) {\n  if (ev?.color) return ev.color;                         // per-event color\n  if (ev?.subject && subjectColors[ev.subject]) return subjectColors[ev.subject]; // per-subject\n  return autoColor(ev?.subject);                          // auto\n}\n\nfunction brighten(hex, amount = 40) {\n  const r = Math.min(255, parseInt(hex.slice(1,3),16) + amount);\n  const g = Math.min(255, parseInt(hex.slice(3,5),16) + amount);\n  const b = Math.min(255, parseInt(hex.slice(5,7),16) + amount);\n  return '#'+[r,g,b].map(v=>v.toString(16).padStart(2,'0')).join('');\n}\n\n// Palette swatches\nfunction buildPaletteRow() {\n  const row = document.getElementById('palette-row');\n  if (!row) return;\n  row.innerHTML = PALETTE.map(c =>\n    `<span class=\"color-swatch\" style=\"background:${c}\" onclick=\"pickPaletteColor('${c}')\" title=\"${c}\"></span>`\n  ).join('');\n}\n\nfunction pickPaletteColor(c) {\n  document.getElementById('ev-color').value = c;\n  document.querySelectorAll('.color-swatch').forEach(el =>\n    el.classList.toggle('active', el.style.background === c || el.style.background === hexToRgb(c))\n  );\n}\n\nfunction hexToRgb(hex) {\n  const r=parseInt(hex.slice(1,3),16), g=parseInt(hex.slice(3,5),16), b=parseInt(hex.slice(5,7),16);\n  return `rgb(${r}, ${g}, ${b})`;\n}\n\nfunction onSubjectInput() {\n  const subj = document.getElementById('ev-subject').value.trim();\n  const c = subjectColors[subj] || autoColor(subj);\n  document.getElementById('ev-color').value = c;\n}\n\nfunction saveSubjectColor() {\n  const subj = document.getElementById('ev-subject').value.trim();\n  if (!subj) return;\n  subjectColors[subj] = document.getElementById('ev-color').value;\n  saveSubjectColors();\n  renderScheduleCards();\n  if (viewMode==='cal') renderCalendar();\n}\n\nfunction clearEventColor() {\n  const subj = document.getElementById('ev-subject').value.trim();\n  const c = subjectColors[subj] || autoColor(subj);\n  document.getElementById('ev-color').value = c;\n}\n\n// \u2500\u2500 Duplicate suppression \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Returns true if this event should be suppressed in list view\nfunction isDuplicate(ev) {\n  if (ev.notify) return false; // never suppress notify=ON events\n  const key = (ev.subject||'') + '::' + (ev.unit||'');\n  const evDate = new Date(ev.date);\n  for (const other of schedules) {\n    if (other.eventId === ev.eventId) continue;\n    if ((other.subject||'')+'::'+(other.unit||'') !== key) continue;\n    if (!other.notify) continue;\n    const otherDate = new Date(other.date);\n    const daysDiff = Math.abs((evDate - otherDate) / 86400000);\n    if (daysDiff <= 20) return true; // suppress\n  }\n  return false;\n}\n\n// \u2500\u2500 State \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlet tabs      = JSON.parse(localStorage.getItem('yt_tabs')    || '[]');\nlet recents   = JSON.parse(localStorage.getItem('yt_recent')  || '[]');\nlet notifs    = JSON.parse(localStorage.getItem('yt_notifs')  || '[]');\nlet schedules = JSON.parse(localStorage.getItem('yt_schedule')|| '[]');\nlet activeTabId = localStorage.getItem('yt_active_tab') || ONLINE;\nlet swReg = null, pushSub = null, notifOpen = false, recentOpen = false, renameTabId = null;\nlet videoCache = {}, jsonAreaOpen = false, viewMode = 'list';\nlet calYear = new Date().getFullYear(), calMonth = new Date().getMonth(), calSelected = null, calFilter = 'all';\nlet selectedSet = new Set(), sortedIndices = [], lastClickedSorted = -1, selectionMode = false, longPressTimer = null;\nlet editingEventIdx = -1;\nlet pendingImport = null;\n\nif (!tabs.length) { tabs = [newTab('\u30d7\u30ec\u30a4\u30ea\u30b9\u30c8 1', '')]; saveTabs(); }\nif (!tabs.find(t => t.id === activeTabId) && activeTabId !== ONLINE) activeTabId = ONLINE;\n\nfunction newTab(n, p) { return { id: Date.now().toString(36)+Math.random().toString(36).slice(2,6), name:n, playlistId:p, createdAt:Date.now() }; }\nfunction saveTabs() { localStorage.setItem('yt_tabs', JSON.stringify(tabs)); localStorage.setItem('yt_active_tab', activeTabId); }\nfunction saveRecents() { localStorage.setItem('yt_recent', JSON.stringify(recents)); }\nfunction saveSchedule() { localStorage.setItem('yt_schedule', JSON.stringify(schedules)); syncScheduleToKV(); }\nasync function syncScheduleToKV() {\n  try { await fetch(`${WORKER}/schedules`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({schedules})}); } catch {}\n}\n\n// \u2500\u2500 Init \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n(async () => {\n  const p = new URLSearchParams(location.search);\n\n  // Short code import\n  const code = p.get('code');\n  if (code) {\n    try {\n      const res = await fetch(`${WORKER}/share?code=${encodeURIComponent(code)}`);\n      if (res.ok) {\n        const result = await res.json();\n        if (result.data) showImportModal(result.data);\n      }\n    } catch(e) { console.warn('code import:', e); }\n    history.replaceState({}, '', location.pathname);\n  }\n\n  if ('serviceWorker' in navigator) {\n    try { swReg = await navigator.serviceWorker.register('/sw.js'); await navigator.serviceWorker.ready; pushSub = await swReg.pushManager.getSubscription(); updatePushBadge(); } catch {}\n  }\n  buildPaletteRow();\n  renderTabBar(); renderApp(); updateNotifBadge();\n  if (schedules.length) renderScheduleCards();\n  setupKeyboard(); updatePushDebug();\n  document.getElementById('ev-period').addEventListener('change', onPeriodChange);\n})();\n\n// \u2500\u2500 Period \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction onPeriodChange() {\n  const v = document.getElementById('ev-period').value;\n  if (v==='1') { document.getElementById('ev-start').value='19:30'; document.getElementById('ev-end').value='21:00'; }\n  else if (v==='2') { document.getElementById('ev-start').value='20:40'; document.getElementById('ev-end').value='23:00'; }\n}\n\n// \u2500\u2500 Keyboard \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction setupKeyboard() {\n  document.addEventListener('keydown', e => {\n    if (activeTabId !== ONLINE) return;\n    const tag = document.activeElement.tagName;\n    if (tag==='INPUT'||tag==='TEXTAREA'||tag==='SELECT') return;\n    if ((e.ctrlKey||e.metaKey) && e.key==='a') { e.preventDefault(); selectAll(); }\n    if ((e.key==='x'||e.key==='X') && !e.ctrlKey && selectedSet.size>0) showDeleteConfirm();\n    if (e.key==='Escape') clearSelection();\n  });\n}\n\n// \u2500\u2500 View \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction toggleView() {\n  viewMode = viewMode==='list' ? 'cal' : 'list';\n  document.getElementById('view-btn').textContent = viewMode==='list' ? '\u30ab\u30ec\u30f3\u30c0\u30fc' : '\u30ea\u30b9\u30c8';\n  document.getElementById('cal-wrap').classList.toggle('show', viewMode==='cal');\n  document.getElementById('list-wrap').style.display = viewMode==='list' ? '' : 'none';\n  if (viewMode==='cal') renderCalendar();\n}\n\n// \u2500\u2500 Calendar filter \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction setCalFilter(f) {\n  calFilter = f;\n  ['all','notify','future'].forEach(id => document.getElementById('filt-'+id).classList.toggle('active', id===f));\n  calSelected = null;\n  document.getElementById('cal-events').style.display = 'none';\n  renderCalendar();\n}\n\nfunction filteredSchedules() {\n  const now = new Date();\n  return schedules.filter(s => {\n    if (calFilter==='notify' && !s.notify) return false;\n    if (calFilter==='future' && new Date(s.date+'T'+(s.startTime||'00:00')) < now) return false;\n    return true;\n  });\n}\n\n// \u2500\u2500 Calendar \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction calMove(d) { calMonth+=d; if(calMonth>11){calMonth=0;calYear++;} if(calMonth<0){calMonth=11;calYear--;} calSelected=null; document.getElementById('cal-events').style.display='none'; renderCalendar(); }\nfunction toDateStr(d) { return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0'); }\n\nfunction renderCalendar() {\n  document.getElementById('cal-title').textContent = calYear+'\u5e74'+(calMonth+1)+'\u6708';\n  const grid = document.getElementById('cal-grid');\n  const days = ['\u65e5','\u6708','\u706b','\u6c34','\u6728','\u91d1','\u571f'];\n  let html = days.map(d=>`<div class=\"cal-head\">${d}</div>`).join('');\n  const first = new Date(calYear, calMonth, 1);\n  const startDow = first.getDay();\n  const daysInMonth = new Date(calYear, calMonth+1, 0).getDate();\n  const prevDays = new Date(calYear, calMonth, 0).getDate();\n  const todayStr = toDateStr(new Date());\n  const evMap = {};\n  filteredSchedules().forEach(s => { if(s.date) evMap[s.date]=(evMap[s.date]||[]).concat(s); });\n  for (let i=startDow-1; i>=0; i--) {\n    const d=prevDays-i, ds=toDateStr(new Date(calYear,calMonth-1,d));\n    html += dayCell(d, ds, evMap[ds]||[], 'other-month');\n  }\n  for (let d=1; d<=daysInMonth; d++) {\n    const ds = toDateStr(new Date(calYear,calMonth,d));\n    const cls = (ds===todayStr?'today':'')+(ds===calSelected?' selected':'');\n    html += dayCell(d, ds, evMap[ds]||[], cls);\n  }\n  const remain = (7-(startDow+daysInMonth)%7)%7;\n  for (let d=1; d<=remain; d++) {\n    const ds = toDateStr(new Date(calYear,calMonth+1,d));\n    html += dayCell(d, ds, evMap[ds]||[], 'other-month');\n  }\n  grid.innerHTML = html;\n  if (calSelected) renderCalEvents(calSelected, evMap[calSelected]||[]);\n}\n\nfunction dayCell(d, ds, events, extra) {\n  const seen = new Set();\n  const dots = events.map(e => {\n    const c = e.notify ? brighten(getEventColor(e), 30) : getEventColor(e);\n    const k = c + (e.notify?'1':'0');\n    if (seen.has(k)) return '';\n    seen.add(k);\n    return `<span class=\"cal-dot\" style=\"background:${c}${e.notify?';box-shadow:0 0 4px '+c:''}\"></span>`;\n  }).join('');\n  return `<div class=\"cal-day ${extra}\" onclick=\"calSelect('${ds}')\"><div class=\"cal-dn\">${d}</div><div class=\"cal-dots\">${dots}</div></div>`;\n}\n\nfunction calSelect(ds) {\n  calSelected = ds;\n  const evMap = {};\n  filteredSchedules().forEach(s => { if(s.date) evMap[s.date]=(evMap[s.date]||[]).concat(s); });\n  renderCalendar();\n  const el = document.getElementById('cal-events');\n  renderCalEvents(ds, evMap[ds]||[]);\n  el.style.display = '';\n}\n\nfunction renderCalEvents(ds, events) {\n  const el = document.getElementById('cal-events');\n  if (!events.length) { el.innerHTML='<div class=\"empty\" style=\"padding:12px\">\u3053\u306e\u65e5\u306e\u4e88\u5b9a\u306f\u3042\u308a\u307e\u305b\u3093</div>'; return; }\n  const rel = getRelative(ds);\n  el.innerHTML = `<div class=\"cal-events-box\"><h4>${ds} <span class=\"s-rel ${rel.cls}\" style=\"font-size:10px\">${rel.text}</span></h4>\n  ${events.map(e => {\n    const origIdx = schedules.findIndex(x => x.eventId===e.eventId);\n    const color = getEventColor(e);\n    const displayColor = e.notify ? brighten(color, 30) : color;\n    const link = e.link?.url || e.zoomUrl || '';\n    return `<div class=\"cal-ev\" style=\"border-left-color:${displayColor};background:${displayColor}18\">\n      <div class=\"cal-ev-sub\">\n        <span style=\"color:${displayColor};font-weight:bold\">${esc(e.subject||'')} <span style=\"font-weight:normal;color:var(--muted);font-size:10px\">${esc(e.unit||'')}</span></span>\n        <span class=\"s-status ${e.status||'normal'}\" style=\"font-size:10px\">${esc(e.statusName||'\u901a\u5e38')}</span>\n      </div>\n      <div class=\"cal-ev-meta\">${esc(e.timeSlot||'')} ${esc(e.startTime||'')}\u301c${esc(e.endTime||'')}${e.isDefaultTime?' (\u30c7\u30d5\u30a9\u30eb\u30c8)':''}</div>\n      ${e.memo?`<div style=\"font-size:10px;color:var(--muted);margin-top:2px\">${esc(e.memo)}</div>`:''}\n      <div class=\"cal-ev-actions\">\n        <label class=\"tog-wrap\" onclick=\"event.stopPropagation()\">\n          <svg width=\"10\" height=\"10\" viewBox=\"0 0 24 24\" fill=\"var(--muted)\"><path d=\"M12 22c1.1 0 2-.9 2-2h-4c0 1.1.9 2 2 2zm6-6v-5c0-3.07-1.64-5.64-4.5-6.32V4c0-.83-.67-1.5-1.5-1.5s-1.5.67-1.5 1.5v.68C7.63 5.36 6 7.92 6 11v5l-2 2v1h16v-1l-2-2z\"/></svg>\n          <label class=\"tog\"><input type=\"checkbox\" ${e.notify?'checked':''} onchange=\"schedSet(${origIdx},'notify',this.checked);calSelect('${ds}')\"><span class=\"tog-sl\" style=\"${e.notify?'background:'+displayColor:''}\"></span></label>\n        </label>\n        <label class=\"tog-wrap\">\u5b8c\u4e86<label class=\"tog done\"><input type=\"checkbox\" ${e.completed?'checked':''} onchange=\"schedSet(${origIdx},'completed',this.checked);calSelect('${ds}')\"><span class=\"tog-sl\"></span></label></label>\n        ${link?`<button class=\"s-link-btn\" onclick=\"window.open('${link}','_blank')\"><svg viewBox=\"0 0 24 24\"><path d=\"M19 19H5V5h7V3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2v-7h-2v7zM14 3v2h3.59l-9.83 9.83 1.41 1.41L19 6.41V10h2V3h-7z\"/></svg>\u53c2\u52a0/\u958b\u304f</button>`:''}\n        <button class=\"sel-btn\" style=\"font-size:10px;padding:2px 6px\" onclick=\"openAddEvent(${origIdx})\">\u7de8\u96c6</button>\n      </div>\n    </div>`;\n  }).join('')}</div>`;\n}\n\n// \u2500\u2500 Selection \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction toggleSelect(sp){const i=sortedIndices[sp];if(selectedSet.has(i))selectedSet.delete(i);else selectedSet.add(i);lastClickedSorted=sp;updateSelUI();}\nfunction shiftSelect(sp){if(lastClickedSorted===-1){toggleSelect(sp);return;}const f=Math.min(lastClickedSorted,sp),t=Math.max(lastClickedSorted,sp);for(let i=f;i<=t;i++)selectedSet.add(sortedIndices[i]);lastClickedSorted=sp;updateSelUI();}\nfunction selectAll(){sortedIndices.forEach(i=>selectedSet.add(i));lastClickedSorted=sortedIndices.length-1;updateSelUI();}\nfunction clearSelection(){selectedSet.clear();lastClickedSorted=-1;if(isMobile())exitSelectionMode();else updateSelUI();}\nfunction exitSelectionMode(){selectionMode=false;selectedSet.clear();lastClickedSorted=-1;updateSelUI();}\nfunction updateSelUI(){\n  const n=selectedSet.size;\n  if(!isMobile()){\n    document.getElementById('sel-toolbar').classList.toggle('show',n>0);\n    document.getElementById('sel-count-text').textContent=n+'\u4ef6\u9078\u629e\u4e2d';\n    document.getElementById('mobile-sel-banner').classList.remove('show');\n  }else{\n    document.getElementById('sel-toolbar').classList.remove('show');\n    document.getElementById('mobile-sel-banner').classList.toggle('show',selectionMode);\n    document.getElementById('mb-sel-txt').textContent=selectionMode?n+'\u4ef6\u9078\u629e\u4e2d':'\u9078\u629e\u30e2\u30fc\u30c9';\n    document.getElementById('mb-del-btn').style.display=(selectionMode&&n>0)?'flex':'none';\n  }\n  document.querySelectorAll('.s-card[data-sp]').forEach(card=>{\n    card.classList.toggle('selected',selectedSet.has(sortedIndices[parseInt(card.dataset.sp)]));\n  });\n}\nfunction onCardTouchStart(e,sp){longPressTimer=setTimeout(()=>{longPressTimer=null;selectionMode=true;selectedSet.clear();selectedSet.add(sortedIndices[sp]);lastClickedSorted=sp;navigator.vibrate?.(30);updateSelUI();},500);}\nfunction onCardTouchEnd(){clearTimeout(longPressTimer);longPressTimer=null;}\nfunction onCardTouchMove(){clearTimeout(longPressTimer);longPressTimer=null;}\nfunction onCardClick(e,sp){if(!isMobile())return;if(!selectionMode)return;e.preventDefault();toggleSelect(sp);}\nfunction onCheckboxClick(e,sp){e.stopPropagation();if(e.shiftKey)shiftSelect(sp);else toggleSelect(sp);}\nfunction showDeleteConfirm(){if(!selectedSet.size)return;document.getElementById('delete-msg').textContent=selectedSet.size+'\u4ef6\u306e\u4e88\u5b9a\u3092\u524a\u9664\u3057\u307e\u3059\u304b\uff1f';document.getElementById('delete-modal').classList.add('open');}\nfunction confirmDelete(){[...selectedSet].sort((a,b)=>b-a).forEach(i=>schedules.splice(i,1));saveSchedule();clearSelection();closeModal('delete-modal');renderScheduleCards();if(viewMode==='cal')renderCalendar();}\n\n// \u2500\u2500 Add/Edit event \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction openAddEvent(idx=-1) {\n  editingEventIdx = idx;\n  const isEdit = idx >= 0;\n  document.getElementById('event-modal-title').textContent = isEdit ? '\u4e88\u5b9a\u3092\u7de8\u96c6' : '\u4e88\u5b9a\u3092\u8ffd\u52a0';\n  document.getElementById('ev-err').style.display = 'none';\n  buildPaletteRow();\n  if (isEdit) {\n    const s = schedules[idx];\n    document.getElementById('ev-subject').value = s.subject||'';\n    document.getElementById('ev-unit').value = s.unit||'';\n    document.getElementById('ev-date').value = s.date||'';\n    document.getElementById('ev-period').value = s.period||1;\n    document.getElementById('ev-start').value = s.startTime||'19:30';\n    document.getElementById('ev-end').value = s.endTime||'21:00';\n    document.getElementById('ev-status').value = s.status||'normal';\n    document.getElementById('ev-notify').value = (s.notifyBefore||[60,30,10]).join(',');\n    document.getElementById('ev-link').value = s.link?.url||s.zoomUrl||'';\n    document.getElementById('ev-memo').value = s.memo||'';\n    document.getElementById('ev-color').value = s.color || subjectColors[s.subject] || autoColor(s.subject);\n  } else {\n    document.getElementById('ev-subject').value = '';\n    document.getElementById('ev-unit').value = '';\n    document.getElementById('ev-date').value = new Date().toISOString().slice(0,10);\n    document.getElementById('ev-period').value = '1';\n    document.getElementById('ev-start').value = '19:30';\n    document.getElementById('ev-end').value = '21:00';\n    document.getElementById('ev-status').value = 'normal';\n    document.getElementById('ev-notify').value = '60,30,10';\n    document.getElementById('ev-link').value = '';\n    document.getElementById('ev-memo').value = '';\n    document.getElementById('ev-color').value = autoColor('');\n  }\n  document.getElementById('event-modal').classList.add('open');\n}\n\nfunction submitEvent() {\n  const subject   = document.getElementById('ev-subject').value.trim();\n  const date      = document.getElementById('ev-date').value;\n  const errEl     = document.getElementById('ev-err');\n  if (!subject) { errEl.textContent='\u6559\u79d1\u3092\u5165\u529b\u3057\u3066\u304f\u3060\u3055\u3044'; errEl.style.display='block'; return; }\n  if (!date)    { errEl.textContent='\u65e5\u4ed8\u3092\u5165\u529b\u3057\u3066\u304f\u3060\u3055\u3044';   errEl.style.display='block'; return; }\n  const period    = parseInt(document.getElementById('ev-period').value)||0;\n  const startTime = document.getElementById('ev-start').value;\n  const endTime   = document.getElementById('ev-end').value;\n  const statusVal = document.getElementById('ev-status').value;\n  const statusNames = {normal:'\u901a\u5e38\u6388\u696d',h_class:'H\u30af\u30e9\u30b9',s_class:'S\u30af\u30e9\u30b9'};\n  const notifyBefore = document.getElementById('ev-notify').value.split(',').map(v=>parseInt(v.trim())).filter(n=>!isNaN(n));\n  const linkUrl   = document.getElementById('ev-link').value.trim();\n  const colorVal  = document.getElementById('ev-color').value;\n  const weekday   = ['\u65e5','\u6708','\u706b','\u6c34','\u6728','\u91d1','\u571f'][new Date(date).getDay()];\n  // Auto-save to subject color if it's a new event\n  const autoC = autoColor(subject);\n  const existingColor = subjectColors[subject];\n  const entry = {\n    eventId: editingEventIdx>=0 ? schedules[editingEventIdx].eventId : 'evt_'+Math.random().toString(36).slice(2,10),\n    subject, unit: document.getElementById('ev-unit').value.trim(), date,\n    displayDate: date.slice(5).replace('-','/'), weekday, period,\n    timeSlot: period>0?period+'\u9650':'',\n    startTime, endTime, isDefaultTime: false,\n    status: statusVal, statusName: statusNames[statusVal]||'\u901a\u5e38\u6388\u696d',\n    zoomUrl: linkUrl,\n    link: linkUrl ? {url:linkUrl,type:linkUrl.includes('zoom')?'zoom':'external',target:'_blank'} : {url:''},\n    color: colorVal !== autoC && colorVal !== existingColor ? colorVal : undefined,\n    notify: editingEventIdx>=0 ? schedules[editingEventIdx].notify : false,\n    notifyBefore, memo: document.getElementById('ev-memo').value.trim(),\n    completed: editingEventIdx>=0 ? schedules[editingEventIdx].completed : false,\n    confidence: 1.0,\n  };\n  if (editingEventIdx>=0) schedules[editingEventIdx]=entry;\n  else schedules.push(entry);\n  saveSchedule();\n  closeModal('event-modal');\n  renderScheduleCards();\n  if (viewMode==='cal') renderCalendar();\n}\n\n// \u2500\u2500 Schedule JSON \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction toggleJsonArea(){jsonAreaOpen=!jsonAreaOpen;document.getElementById('sched-json').classList.toggle('open',jsonAreaOpen);document.getElementById('sched-load-row').style.display=jsonAreaOpen?'flex':'none';if(jsonAreaOpen)document.getElementById('sched-json').focus();}\n\nfunction loadScheduleJson(){\n  const raw=document.getElementById('sched-json').value.trim();\n  const errEl=document.getElementById('sched-err');errEl.style.display='none';\n  try{\n    let input=JSON.parse(raw);let arr=Array.isArray(input)?input:(input.schedule||[]);\n    if(!arr.length)throw new Error('schedule\u304c\u7a7a\u3067\u3059');\n    let added=0,skipped=0;\n    arr.forEach(s=>{\n      s=fillDefaultTime(s);\n      const dup=schedules.find(x=>x.eventId===s.eventId||(x.subject===s.subject&&x.unit===s.unit&&x.date===s.date&&x.period===s.period&&x.status===s.status));\n      if(dup){skipped++;return;}schedules.push(s);added++;\n    });\n    saveSchedule();toggleJsonArea();document.getElementById('sched-json').value='';\n    renderScheduleCards();if(viewMode==='cal')renderCalendar();\n    if(skipped){errEl.textContent=`${added}\u4ef6\u8ffd\u52a0\u3001${skipped}\u4ef6\u91cd\u8907\u30b9\u30ad\u30c3\u30d7`;errEl.style.display='block';}\n  }catch(e){errEl.textContent='JSON\u30a8\u30e9\u30fc: '+e.message;errEl.style.display='block';}\n}\n\nfunction clearSchedule(){if(!confirm('\u5168\u4e88\u5b9a\u3092\u524a\u9664\u3057\u307e\u3059\u304b\uff1f'))return;schedules=[];saveSchedule();selectedSet.clear();renderScheduleCards();if(viewMode==='cal')renderCalendar();}\n\nfunction fillDefaultTime(s){\n  if(!s.startTime){\n    if(s.period===1){s.startTime='19:30';s.endTime=s.endTime||'21:00';s.isDefaultTime=true;}\n    else if(s.period===2){s.startTime='20:40';s.endTime=s.endTime||'23:00';s.isDefaultTime=true;}\n    else{s.startTime='00:00';s.isDefaultTime=true;}\n  }else{s.isDefaultTime=false;if(!s.endTime)s.endTime=calcEnd(s.startTime);}\n  return s;\n}\nfunction calcEnd(start){let[h,m]=start.split(':').map(Number);m+=90;h+=Math.floor(m/60);m%=60;return String(h).padStart(2,'0')+':'+String(m).padStart(2,'0');}\nfunction getRelative(ds){\n  const today=new Date();today.setHours(0,0,0,0);\n  const target=new Date(ds);target.setHours(0,0,0,0);\n  const diff=Math.floor((target-today)/86400000);\n  if(diff===0)return{text:'\u4eca\u65e5',cls:'today'};if(diff===1)return{text:'\u660e\u65e5',cls:'future'};\n  if(diff===2)return{text:'\u660e\u5f8c\u65e5',cls:'future'};if(diff===-1)return{text:'\u6628\u65e5',cls:'past'};\n  if(diff===-2)return{text:'\u4e00\u6628\u65e5',cls:'past'};if(diff>2)return{text:`${diff}\u65e5\u5f8c`,cls:'future'};\n  return{text:`${Math.abs(diff)}\u65e5\u524d`,cls:'past'};\n}\n\n// \u2500\u2500 Render cards (grouped by subject+unit) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlet groupExpanded = {}; // key \u2192 bool\n\nfunction renderScheduleCards() {\n  const container = document.getElementById('sched-cards');\n  if (!schedules.length) {\n    container.innerHTML = '<div class=\"empty\">\u300c\uff0b \u8ffd\u52a0\u300d\u307e\u305f\u306fJSON\u3092\u8aad\u307f\u8fbc\u3093\u3067\u304f\u3060\u3055\u3044</div>';\n    sortedIndices = []; updateSelUI(); return;\n  }\n\n  const now = new Date();\n  // Sort all schedules\n  const withIdx = schedules.map((s,i) => ({s,i}));\n  withIdx.sort((a,b) => {\n    const ta=new Date(a.s.date+'T'+(a.s.startTime||'00:00'));\n    const tb=new Date(b.s.date+'T'+(b.s.startTime||'00:00'));\n    const ap=ta<now, bp=tb<now;\n    if(ap!==bp)return ap?1:-1;if(!ap&&!bp)return ta-tb;return tb-ta;\n  });\n  sortedIndices = withIdx.map(x => x.i);\n\n  // Group by subject + unit\n  const groups = {};\n  const groupOrder = [];\n  withIdx.forEach(({s,i}, sp) => {\n    const key = (s.subject||'') + '::' + (s.unit||'');\n    if (!groups[key]) { groups[key] = []; groupOrder.push(key); }\n    groups[key].push({s,i,sp});\n  });\n\n  let html = '';\n  let pastDividerAdded = false;\n\n  groupOrder.forEach(key => {\n    const items = groups[key];\n    const firstEv = items[0].s;\n    const color = getEventColor(firstEv);\n    const displayColor = items.some(x=>x.s.notify) ? brighten(color,20) : color;\n    const expanded = groupExpanded[key] !== false; // default expanded\n    const hasMultiple = items.length > 1;\n\n    // Past divider \u2014 check if first item of group is past\n    const firstDate = new Date(items[0].s.date+'T'+(items[0].s.startTime||'00:00'));\n    if (!pastDividerAdded && firstDate < now) {\n      pastDividerAdded = true;\n      html += '<div class=\"s-divider\">\u2500\u2500\u2500 \u904e\u53bb\u306e\u4e88\u5b9a \u2500\u2500\u2500</div>';\n    }\n\n    html += `<div class=\"sched-group\">`;\n\n    if (hasMultiple) {\n      html += `<div class=\"sched-group-header\" onclick=\"toggleGroup('${key.replace(/'/g,\"\\\\'\")}')\">\n        <span class=\"sgh-dot\" style=\"background:${displayColor}\"></span>\n        <span class=\"sgh-name\" style=\"color:${displayColor}\">${esc(firstEv.subject||'')} <span style=\"font-weight:normal;font-size:10px;color:var(--muted)\">${esc(firstEv.unit||'')}</span></span>\n        <span class=\"sgh-count\">${items.length}\u4ef6</span>\n        <span class=\"sgh-toggle\">${expanded ? '\u25b2' : '\u25bc'}</span>\n      </div>`;\n    }\n\n    html += `<div class=\"group-events ${hasMultiple && !expanded ? 'collapsed' : ''}\" id=\"grp-${btoa(encodeURIComponent(key)).replace(/=/g,'')}\">`;\n\n    items.forEach(({s,i,sp}) => {\n      const rel = getRelative(s.date);\n      const eColor = getEventColor(s);\n      const eDisplay = s.notify ? brighten(eColor, 30) : eColor;\n      const link = s.link?.url || s.zoomUrl || '';\n      const dup = isDuplicate(s);\n      const sel = selectedSet.has(i) ? 'selected' : '';\n\n      html += `<div class=\"s-card ${s.notify?'notify-on':''} ${s.notify?'notify-bright':''} ${s.completed?'completed':''} ${dup?'dim-duplicate':''} ${sel}\" data-sp=\"${sp}\"\n        style=\"border-top:1px solid ${eDisplay}22;${s.notify?'border-left-color:'+eDisplay:''}\"\n        onclick=\"onCardClick(event,${sp})\"\n        ontouchstart=\"onCardTouchStart(event,${sp})\"\n        ontouchend=\"onCardTouchEnd()\"\n        ontouchmove=\"onCardTouchMove()\">\n        <div class=\"s-cb-col\" onclick=\"onCheckboxClick(event,${sp})\">\n          <div class=\"s-checkbox\"><svg viewBox=\"0 0 12 12\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><polyline points=\"1,6 4,10 11,2\"/></svg></div>\n        </div>\n        <div class=\"s-body\">\n          <div class=\"s-head\">\n            <div>\n              ${!hasMultiple?`<div class=\"s-subject\" style=\"color:${eDisplay}\">${esc(s.subject||'')} <span style=\"font-size:11px;color:var(--muted);font-weight:normal\">${esc(s.unit||'')}</span></div>`:''}\n              ${dup?`<div style=\"font-size:10px;color:var(--muted)\">\u901a\u77e5ON\u65e5\u306e\u540c\u4e00\u4e88\u5b9a</div>`:''}\n            </div>\n            <div style=\"display:flex;gap:5px;align-items:center\">\n              <label class=\"tog-wrap\" onclick=\"event.stopPropagation()\">\n                <svg width=\"10\" height=\"10\" viewBox=\"0 0 24 24\" fill=\"var(--muted)\"><path d=\"M12 22c1.1 0 2-.9 2-2h-4c0 1.1.9 2 2 2zm6-6v-5c0-3.07-1.64-5.64-4.5-6.32V4c0-.83-.67-1.5-1.5-1.5s-1.5.67-1.5 1.5v.68C7.63 5.36 6 7.92 6 11v5l-2 2v1h16v-1l-2-2z\"/></svg>\n                <label class=\"tog\"><input type=\"checkbox\" ${s.notify?'checked':''} onchange=\"schedSet(${i},'notify',this.checked)\"><span class=\"tog-sl\" style=\"${s.notify?'background:'+eDisplay:''}\"></span></label>\n              </label>\n              <button class=\"sel-btn\" style=\"font-size:10px;padding:2px 6px\" onclick=\"event.stopPropagation();openAddEvent(${i})\">\u7de8\u96c6</button>\n            </div>\n          </div>\n          <div class=\"s-date\">\n            <svg width=\"10\" height=\"10\" viewBox=\"0 0 24 24\" fill=\"var(--muted)\"><path d=\"M19 4h-1V2h-2v2H8V2H6v2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 16H5V9h14v11z\"/></svg>\n            ${esc(s.date||'')} ${esc(s.weekday||'')} ${esc(s.timeSlot||'')}\n          </div>\n          <div class=\"s-time\">\n            <svg width=\"11\" height=\"11\" viewBox=\"0 0 24 24\" fill=\"var(--muted)\"><path d=\"M12 2C6.5 2 2 6.5 2 12s4.5 10 10 10 10-4.5 10-10S17.5 2 12 2zm.5 5v5.25l4.5 2.67-.75 1.23L11 13V7h1.5z\"/></svg>\n            ${esc(s.startTime||'')} ~ ${esc(s.endTime||'')}${s.isDefaultTime?'<span class=\"s-def\">(\u30c7\u30d5\u30a9\u30eb\u30c8)</span>':''}\n          </div>\n          <div class=\"s-badges\">\n            <span class=\"s-rel ${rel.cls}\">${rel.text}</span>\n            <span class=\"s-status ${s.status||'normal'}\">${esc(s.statusName||'\u901a\u5e38\u6388\u696d')}</span>\n            ${link?`<button class=\"s-link-btn\" onclick=\"event.stopPropagation();window.open('${link}','_blank')\"><svg viewBox=\"0 0 24 24\"><path d=\"M19 19H5V5h7V3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2v-7h-2v7zM14 3v2h3.59l-9.83 9.83 1.41 1.41L19 6.41V10h2V3h-7z\"/></svg>\u53c2\u52a0/\u958b\u304f</button>`:''}\n          </div>\n          ${s.notifyBefore?.length?`<div style=\"font-size:10px;color:var(--muted)\">\u901a\u77e5: ${s.notifyBefore.join(', ')}\u5206\u524d</div>`:''}\n          <div onclick=\"event.stopPropagation()\">\n            <input type=\"text\" value=\"${esc(s.memo||'')}\" placeholder=\"\u30e1\u30e2\" onchange=\"schedSet(${i},'memo',this.value)\">\n          </div>\n          <div onclick=\"event.stopPropagation()\">\n            <label class=\"tog-wrap\">\u5b8c\u4e86<label class=\"tog done\"><input type=\"checkbox\" ${s.completed?'checked':''} onchange=\"schedSet(${i},'completed',this.checked)\"><span class=\"tog-sl\"></span></label></label>\n          </div>\n        </div>\n      </div>`;\n    });\n    html += `</div></div>`;\n  });\n\n  container.innerHTML = html;\n  updateSelUI();\n}\n\nfunction toggleGroup(key) {\n  groupExpanded[key] = groupExpanded[key] === false ? true : false;\n  renderScheduleCards();\n}\n\nfunction schedSet(idx,key,val){if(idx<0||idx>=schedules.length)return;schedules[idx][key]=val;saveSchedule();if(key==='notify'||key==='completed'){renderScheduleCards();if(viewMode==='cal')renderCalendar();}}\n\n// \u2500\u2500 Share (Worker KV short code) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function createShareCode(data) {\n  const res = await fetch(`${WORKER}/share`, {\n    method: 'POST',\n    headers: {'Content-Type':'application/json'},\n    body: JSON.stringify({data})\n  });\n  if (!res.ok) throw new Error(`HTTP ${res.status}`);\n  const result = await res.json();\n  return result;\n}\n\n// Playlist share\nfunction openShare() {\n  document.getElementById('share-checks').innerHTML = tabs.map(t=>`\n    <label style=\"display:flex;align-items:center;gap:8px;margin-bottom:8px;font-size:12px;cursor:pointer\">\n      <input type=\"checkbox\" value=\"${t.id}\" checked style=\"accent-color:var(--accent)\">\n      <span>${esc(t.name)}</span>\n      <span style=\"font-size:10px;color:var(--muted)\">${t.playlistId||'\u672a\u8a2d\u5b9a'}</span>\n    </label>`).join('');\n  document.getElementById('share-result').style.display = 'none';\n  document.getElementById('share-loading').style.display = 'none';\n  document.getElementById('share-modal').classList.add('open');\n}\n\nfunction getSelectedTabs() {\n  const checked = [...document.querySelectorAll('#share-checks input:checked')].map(el=>el.value);\n  return tabs.filter(t=>checked.includes(t.id)).map(t=>({name:t.name,playlistId:t.playlistId}));\n}\n\nasync function generateShareUrl() {\n  const selected = getSelectedTabs();\n  if (!selected.length) return;\n  const loading = document.getElementById('share-loading');\n  loading.style.display = 'block';\n  try {\n    const payload = {type:'playlist', data:selected};\n    const result = await createShareCode(payload);\n    const url = `${location.origin}/?code=${result.code}`;\n    document.getElementById('share-url-text').textContent = url;\n    document.getElementById('share-result').style.display = 'block';\n    document.getElementById('share-result').dataset.json = JSON.stringify(selected);\n  } catch(e) { alert('\u751f\u6210\u30a8\u30e9\u30fc: '+e.message); }\n  finally { loading.style.display = 'none'; }\n}\n\nfunction copyShareUrl() { navigator.clipboard.writeText(document.getElementById('share-url-text').textContent).then(()=>alert('URL\u3092\u30b3\u30d4\u30fc\u3057\u307e\u3057\u305f')); }\nfunction copyShareJson() { navigator.clipboard.writeText(document.getElementById('share-result').dataset.json||'[]').then(()=>alert('JSON\u3092\u30b3\u30d4\u30fc\u3057\u307e\u3057\u305f')); }\n\n// Schedule share\nfunction openSchedShare() {\n  const checks = document.getElementById('sched-share-checks');\n  checks.innerHTML = schedules.map((s,i) => {\n    const color = getEventColor(s);\n    return `<label style=\"display:flex;align-items:center;gap:8px;margin-bottom:6px;font-size:12px;cursor:pointer\">\n      <input type=\"checkbox\" value=\"${i}\" checked style=\"accent-color:${color}\">\n      <span style=\"color:${color}\">${esc(s.subject||'')}</span>\n      <span style=\"font-size:10px;color:var(--muted)\">${esc(s.unit||'')} ${esc(s.date||'')}</span>\n    </label>`;\n  }).join('');\n  document.getElementById('sched-share-result').style.display = 'none';\n  document.getElementById('sched-share-loading').style.display = 'none';\n  document.getElementById('sched-share-modal').classList.add('open');\n}\nfunction schedShareSelectAll(){document.querySelectorAll('#sched-share-checks input').forEach(el=>el.checked=true);}\nfunction schedShareSelectNone(){document.querySelectorAll('#sched-share-checks input').forEach(el=>el.checked=false);}\n\nfunction getSelectedSchedules() {\n  const checked = [...document.querySelectorAll('#sched-share-checks input:checked')].map(el=>parseInt(el.value));\n  return checked.map(i=>schedules[i]).filter(Boolean);\n}\n\nasync function generateSchedShareUrl() {\n  const sel = getSelectedSchedules();\n  if (!sel.length) return;\n  const loading = document.getElementById('sched-share-loading');\n  loading.style.display = 'block';\n  try {\n    const payload = {type:'schedule', data:sel};\n    const result = await createShareCode(payload);\n    const url = `${location.origin}/?code=${result.code}`;\n    document.getElementById('sched-share-url').textContent = url;\n    document.getElementById('sched-share-result').style.display = 'block';\n    document.getElementById('sched-share-result').dataset.json = JSON.stringify(sel);\n  } catch(e) { alert('\u751f\u6210\u30a8\u30e9\u30fc: '+e.message); }\n  finally { loading.style.display = 'none'; }\n}\nfunction copySchedShareUrl(){navigator.clipboard.writeText(document.getElementById('sched-share-url').textContent).then(()=>alert('URL\u3092\u30b3\u30d4\u30fc\u3057\u307e\u3057\u305f'));}\nfunction copySchedShareJson(){navigator.clipboard.writeText(document.getElementById('sched-share-result').dataset.json||'[]').then(()=>alert('JSON\u3092\u30b3\u30d4\u30fc\u3057\u307e\u3057\u305f'));}\n\n// \u2500\u2500 Import \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction showImportModal(payload) {\n  pendingImport = payload;\n  const isSchedule = payload?.type === 'schedule';\n  const items = isSchedule ? payload.data : (payload.data || (Array.isArray(payload)?payload:[]));\n  document.getElementById('import-title').textContent = isSchedule ? '\u4e88\u5b9a\u3092\u30a4\u30f3\u30dd\u30fc\u30c8' : '\u30d7\u30ec\u30a4\u30ea\u30b9\u30c8\u3092\u30a4\u30f3\u30dd\u30fc\u30c8';\n  document.getElementById('import-checks').innerHTML = items.map((item,i) => {\n    if (isSchedule) {\n      const color = getEventColor(item);\n      return `<label style=\"display:flex;align-items:center;gap:8px;margin-bottom:6px;font-size:12px;cursor:pointer\">\n        <input type=\"checkbox\" value=\"${i}\" checked style=\"accent-color:${color}\">\n        <span style=\"color:${color}\">${esc(item.subject||'')}</span>\n        <span style=\"font-size:10px;color:var(--muted)\">${esc(item.unit||'')} ${esc(item.date||'')}</span>\n      </label>`;\n    } else {\n      return `<label style=\"display:flex;align-items:center;gap:8px;margin-bottom:6px;font-size:12px;cursor:pointer\">\n        <input type=\"checkbox\" value=\"${i}\" checked style=\"accent-color:var(--accent)\">\n        <span>${esc(item.name||'\u7121\u984c')}</span>\n        <span style=\"font-size:10px;color:var(--muted)\">${esc(item.playlistId||'')}</span>\n      </label>`;\n    }\n  }).join('');\n  document.getElementById('import-modal').classList.add('open');\n}\n\nfunction confirmImport() {\n  if (!pendingImport) return closeModal('import-modal');\n  const payload = pendingImport;\n  const isSchedule = payload?.type === 'schedule';\n  const items = isSchedule ? payload.data : (payload.data||(Array.isArray(payload)?payload:[]));\n  const checked = [...document.querySelectorAll('#import-checks input:checked')].map(el=>parseInt(el.value));\n  if (isSchedule) {\n    let added=0, skipped=0;\n    checked.forEach(i => {\n      const s = fillDefaultTime({...items[i]});\n      const dup = schedules.find(x=>x.eventId===s.eventId||(x.subject===s.subject&&x.unit===s.unit&&x.date===s.date));\n      if (dup) { skipped++; return; }\n      schedules.push(s); added++;\n    });\n    saveSchedule(); renderScheduleCards(); if(viewMode==='cal')renderCalendar();\n    if (skipped) alert(`${added}\u4ef6\u8ffd\u52a0\u3001${skipped}\u4ef6\u306f\u91cd\u8907\u306e\u305f\u3081\u30b9\u30ad\u30c3\u30d7`);\n  } else {\n    checked.forEach(i => {\n      const d = items[i]; if(!d) return;\n      const tab = newTab(d.name||'\u7121\u984c', d.playlistId||'');\n      tabs.push(tab);\n      const p = document.createElement('div'); p.className='pane'; p.id='pane-'+tab.id;\n      document.getElementById('app').appendChild(p);\n    });\n    saveTabs(); syncPlaylistsToGitHub(); renderTabBar();\n  }\n  pendingImport = null;\n  closeModal('import-modal');\n}\n\n// \u2500\u2500 Tab system \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction renderTabBar(){\n  const bar=document.getElementById('tabbar'),addBtn=bar.querySelector('.tab-add');\n  bar.querySelectorAll('.tab-item:not(.pinned)').forEach(el=>el.remove());\n  document.getElementById('online-tab').classList.toggle('active',activeTabId===ONLINE);\n  tabs.forEach(tab=>{\n    const el=document.createElement('div');el.className='tab-item'+(tab.id===activeTabId?' active':'');el.dataset.id=tab.id;\n    el.innerHTML=`<svg class=\"tab-icon\" viewBox=\"0 0 24 24\"><path d=\"${tab.playlistId?'M8 5v14l11-7z':'M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm0 18c-4.42 0-8-3.58-8-8s3.58-8 8-8 8 3.58 8 8-3.58 8-8 8z'}\"/></svg><span class=\"tab-name\">${esc(tab.name)}</span><button class=\"tab-close\">\u00d7</button>`;\n    el.querySelector('.tab-close').addEventListener('click',e=>{e.stopPropagation();closeTab(tab.id);});\n    el.addEventListener('click',()=>switchTab(tab.id));\n    el.addEventListener('dblclick',()=>openRename(tab.id));\n    bar.insertBefore(el,addBtn);\n  });\n}\nfunction renderApp(){\n  const app=document.getElementById('app');\n  app.querySelectorAll('.pane:not(#pane-online)').forEach(el=>el.remove());\n  tabs.forEach(tab=>{if(!document.getElementById('pane-'+tab.id)){const p=document.createElement('div');p.className='pane';p.id='pane-'+tab.id;app.appendChild(p);}});\n  updateActivePane();\n}\nfunction updateActivePane(){\n  document.querySelectorAll('.pane').forEach(el=>{\n    const isOnline=activeTabId===ONLINE&&el.id==='pane-online';\n    const active=isOnline||(el.id==='pane-'+activeTabId);\n    el.classList.toggle('active',active);\n    if(active&&el.id!=='pane-online'&&!el.children.length){const tab=tabs.find(t=>t.id===activeTabId);if(tab)renderPane(tab);}\n  });\n}\nfunction switchToOnline(){activeTabId=ONLINE;saveTabs();renderTabBar();updateActivePane();}\nfunction switchTab(id){\n  activeTabId=id;saveTabs();\n  document.getElementById('online-tab').classList.remove('active');\n  document.querySelectorAll('.tab-item:not(.pinned)').forEach(el=>el.classList.toggle('active',el.dataset.id===id));\n  document.querySelectorAll('.pane').forEach(el=>{const active=el.id==='pane-'+id;el.classList.toggle('active',active);if(active&&!el.children.length){const tab=tabs.find(t=>t.id===id);if(tab)renderPane(tab);}});\n}\nfunction addTab(){const tab=newTab('\u65b0\u3057\u3044\u30bf\u30d6','');tabs.push(tab);activeTabId=tab.id;saveTabs();const p=document.createElement('div');p.className='pane';p.id='pane-'+tab.id;document.getElementById('app').appendChild(p);renderSetup(p,tab);renderTabBar();updateActivePane();}\nfunction closeTab(id){\n  if(tabs.length===1)return;\n  const idx=tabs.findIndex(t=>t.id===id),tab=tabs[idx];\n  recents.unshift({...tab,deletedAt:Date.now()});if(recents.length>20)recents=recents.slice(0,20);saveRecents();\n  tabs.splice(idx,1);document.getElementById('pane-'+id)?.remove();\n  if(activeTabId===id)activeTabId=tabs[Math.min(idx,tabs.length-1)].id;\n  saveTabs();syncPlaylistsToGitHub();renderTabBar();updateActivePane();\n}\nfunction renderPane(tab){const p=document.getElementById('pane-'+tab.id);if(!p)return;tab.playlistId?renderVideos(p,tab):renderSetup(p,tab);}\nfunction extractPlaylistId(raw){const m=raw.match(/[?&]list=([A-Za-z0-9_-]+)/);return m?m[1]:raw.trim();}\nfunction renderSetup(pane,tab){\n  pane.innerHTML=`<div class=\"setup-box\"><h2>\u30d7\u30ec\u30a4\u30ea\u30b9\u30c8\u3092\u8a2d\u5b9a</h2>\n    <div class=\"field\"><label>\u30bf\u30d6\u540d</label><input type=\"text\" id=\"sn-${tab.id}\" value=\"${esc(tab.name)}\" placeholder=\"\u30bf\u30d6\u540d\"></div>\n    <div class=\"field\"><label>YouTube URL \u307e\u305f\u306f ID</label><input type=\"text\" id=\"sp-${tab.id}\" value=\"${esc(tab.playlistId)}\" placeholder=\"https://youtube.com/... \u3067\u3082OK\"></div>\n    <div class=\"errmsg\" id=\"se-${tab.id}\"></div>\n    <div class=\"btn-row\"><button class=\"btn-accent\" onclick=\"saveTabPlaylist('${tab.id}')\">\u4fdd\u5b58</button>${tab.playlistId?`<button class=\"btn-outline\" onclick=\"cancelSetup('${tab.id}')\">\u30ad\u30e3\u30f3\u30bb\u30eb</button>`:''}</div>\n  </div>`;\n}\nfunction cancelSetup(tabId){const tab=tabs.find(t=>t.id===tabId);const p=document.getElementById('pane-'+tabId);if(tab?.playlistId&&p)renderVideos(p,tab);}\nfunction saveTabPlaylist(tabId){\n  const raw=document.getElementById(`sp-${tabId}`)?.value.trim()||'';\n  const name=document.getElementById(`sn-${tabId}`)?.value.trim()||'';\n  const errEl=document.getElementById(`se-${tabId}`);\n  const plId=extractPlaylistId(raw);\n  if(!plId){if(errEl){errEl.textContent='URL\u307e\u305f\u306fID\u3092\u5165\u529b\u3057\u3066\u304f\u3060\u3055\u3044';errEl.style.display='block';}return;}\n  const tab=tabs.find(t=>t.id===tabId);if(!tab)return;\n  tab.playlistId=plId;if(name)tab.name=name;delete videoCache[tabId];saveTabs();syncPlaylistsToGitHub();renderTabBar();renderPane(tab);\n}\nasync function renderVideos(pane,tab){\n  pane.innerHTML=`<div class=\"vid-header\"><span style=\"font-size:12px;color:var(--accent)\">${esc(tab.name)}</span><span id=\"vc-${tab.id}\" style=\"font-size:10px;color:var(--muted)\"></span><div style=\"flex:1\"></div><button class=\"btn-outline btn-sm\" onclick=\"editTabPlaylist('${tab.id}')\">\u8a2d\u5b9a</button><button class=\"btn-outline btn-sm\" onclick=\"refreshTab('${tab.id}')\">\u66f4\u65b0</button></div><div id=\"vg-${tab.id}\" class=\"loading\">\u8aad\u307f\u8fbc\u307f\u4e2d...</div>`;\n  if(videoCache[tab.id]){renderGrid(tab.id,videoCache[tab.id]);return;}\n  try{\n    const res=await fetch(`${WORKER}/videos?playlistId=${tab.playlistId}`);const data=await res.json();\n    if(data.error)throw new Error(data.error);videoCache[tab.id]=data;renderGrid(tab.id,data);\n  }catch(e){const el=document.getElementById(`vg-${tab.id}`);if(el)el.innerHTML=`<div class=\"empty\">\u30a8\u30e9\u30fc: ${esc(e.message)}</div>`;}\n}\nfunction renderGrid(tabId,videos){\n  const vc=document.getElementById(`vc-${tabId}`),vg=document.getElementById(`vg-${tabId}`);\n  if(vc)vc.textContent=videos.length+'\u672c';if(!vg)return;\n  if(!videos.length){vg.innerHTML='<div class=\"empty\">\u52d5\u753b\u304c\u3042\u308a\u307e\u305b\u3093</div>';return;}\n  vg.className='video-grid';\n  vg.innerHTML=videos.map(v=>`<div class=\"video-card\" onclick=\"location.href='/player.html?v=${v.id}&t=${encodeURIComponent(v.title)}'\"><img src=\"${v.thumb}\" loading=\"lazy\" onerror=\"this.style.background='var(--bg3)'\"><div class=\"vc-title\">${esc(v.title)}</div></div>`).join('');\n}\nfunction editTabPlaylist(tabId){const tab=tabs.find(t=>t.id===tabId);const p=document.getElementById('pane-'+tabId);if(tab&&p)renderSetup(p,tab);}\nasync function refreshTab(tabId){delete videoCache[tabId];const tab=tabs.find(t=>t.id===tabId);const p=document.getElementById('pane-'+tabId);if(tab&&p)renderVideos(p,tab);}\n\n// \u2500\u2500 Rename \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction openRename(id){renameTabId=id;const tab=tabs.find(t=>t.id===id);document.getElementById('rename-input').value=tab?.name||'';document.getElementById('rename-modal').classList.add('open');setTimeout(()=>{document.getElementById('rename-input').focus();document.getElementById('rename-input').select();},50);}\nfunction confirmRename(){const name=document.getElementById('rename-input').value.trim();if(!name||!renameTabId)return closeModal('rename-modal');const tab=tabs.find(t=>t.id===renameTabId);if(tab){tab.name=name;saveTabs();renderTabBar();}closeModal('rename-modal');}\ndocument.getElementById('rename-input').addEventListener('keydown',e=>{if(e.key==='Enter')confirmRename();if(e.key==='Escape')closeModal('rename-modal');});\n\n// \u2500\u2500 Recents \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction toggleRecent(){recentOpen=!recentOpen;document.getElementById('recent-panel').classList.toggle('open',recentOpen);if(recentOpen)renderRecentList();}\nfunction renderRecentList(){\n  const el=document.getElementById('rp-list');\n  if(!recents.length){el.innerHTML='<div class=\"empty\" style=\"padding:16px\">\u524a\u9664\u3057\u305f\u30bf\u30d6\u306f\u3042\u308a\u307e\u305b\u3093</div>';return;}\n  el.innerHTML=recents.map((r,i)=>`<div class=\"recent-item\"><div class=\"ri-info\"><div class=\"ri-name\">${esc(r.name)}</div><div class=\"ri-pl\">${esc(r.playlistId||'\u672a\u8a2d\u5b9a')}</div><div class=\"ri-time\">${fmtTime(r.deletedAt)}</div></div><button class=\"btn-accent btn-sm\" onclick=\"restoreTab(${i})\">\u5fa9\u5143</button></div>`).join('');\n}\nfunction restoreTab(idx){\n  const r=recents[idx];if(!r)return;\n  const tab={...newTab(r.name,r.playlistId)};tabs.push(tab);recents.splice(idx,1);saveRecents();saveTabs();syncPlaylistsToGitHub();\n  const p=document.createElement('div');p.className='pane';p.id='pane-'+tab.id;document.getElementById('app').appendChild(p);\n  renderTabBar();renderRecentList();\n}\n\n// \u2500\u2500 Sync \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function syncPlaylistsToGitHub(){\n  const pl=tabs.filter(t=>t.playlistId).map(t=>({id:t.playlistId,title:t.name,autoDownload:false}));\n  if(!pl.length)return;\n  try{await fetch(`${WORKER}/playlists`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({playlists:pl})});}catch{}\n}\n\n// \u2500\u2500 Push \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function togglePush(){\n  if(!swReg){alert('Service Worker\u304c\u5229\u7528\u3067\u304d\u307e\u305b\u3093');return;}\n  if(pushSub){await pushSub.unsubscribe();pushSub=null;updatePushBadge();updatePushDebug();return;}\n  const perm=await Notification.requestPermission();if(perm!=='granted'){alert('\u30d6\u30e9\u30a6\u30b6\u306e\u8a2d\u5b9a\u3067\u901a\u77e5\u3092\u8a31\u53ef\u3057\u3066\u304f\u3060\u3055\u3044');return;}\n  if(!VAPID){alert('VAPID_PUBLIC\u304cWorker\u306b\u8a2d\u5b9a\u3055\u308c\u3066\u3044\u307e\u305b\u3093');return;}\n  try{\n    await navigator.serviceWorker.ready;\n    pushSub=await swReg.pushManager.subscribe({userVisibleOnly:true,applicationServerKey:urlB64ToUint8(VAPID)});\n    const res=await fetch(`${WORKER}/subscribe`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({subscription:pushSub.toJSON()})});\n    if(!res.ok)throw new Error(`Worker: ${res.status}`);\n    updatePushBadge();updatePushDebug();\n  }catch(e){alert('\u767b\u9332\u30a8\u30e9\u30fc: '+e.message);}\n}\nfunction updatePushBadge(){const on=!!pushSub;document.getElementById('push-badge').textContent=on?'PUSH ON':'PUSH OFF';document.getElementById('push-badge').className=on?'badge':'badge off';}\nfunction updatePushDebug(){const el=document.getElementById('push-debug');if(!el)return;el.textContent=pushSub?'\u767b\u9332\u6e08: '+pushSub.endpoint.slice(0,50)+'...':'\u672a\u767b\u9332';}\nasync function testLocalNotif(){\n  const perm=await Notification.requestPermission();if(perm!=='granted'){alert('\u901a\u77e5\u3092\u8a31\u53ef\u3057\u3066\u304f\u3060\u3055\u3044');return;}\n  if(swReg)await swReg.showNotification('\u30c6\u30b9\u30c8\u901a\u77e5',{body:'\u901a\u77e5\u304c\u6b63\u5e38\u306b\u5c4a\u3044\u3066\u3044\u307e\u3059',tag:'test'});\n  else new Notification('\u30c6\u30b9\u30c8\u901a\u77e5',{body:'\u901a\u77e5\u304c\u5c4a\u3044\u3066\u3044\u307e\u3059'});\n}\n\nasync function runServerCheck(){\n  const el=document.getElementById('server-check-result');\n  if(!el)return;\n  el.textContent='\u5b9f\u884c\u4e2d...';\n  try{\n    const res=await fetch(`${WORKER}/run-check`);\n    const data=await res.json();\n    if(data.error){el.textContent='\u30a8\u30e9\u30fc: '+data.error;return;}\n    let lines=[];\n    lines.push(`\u8cfc\u8aad\u8005: ${data.subscribers}\u4ef6`);\n    (data.playlists||[]).forEach(p=>{\n      if(p.error)lines.push(`\u2717 ${p.title}: ${p.error}`);\n      else lines.push(`${p.title}: \u5168${p.total} / \u65b0\u7740${p.new}`);\n    });\n    lines.push(`\u4e88\u5b9a\u901a\u77e5: ${data.scheduleSent}\u4ef6\u9001\u4fe1`);\n    if(data.errors?.length)lines.push(...data.errors.map(e=>'\u2717 '+e));\n    el.innerHTML=lines.map(esc).join('<br>');\n  }catch(e){el.textContent='\u901a\u4fe1\u30a8\u30e9\u30fc: '+e.message;}\n}\n\n// \u2500\u2500 Notifications \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction toggleNotifPanel(){notifOpen=!notifOpen;document.getElementById('notif-panel').classList.toggle('open',notifOpen);if(notifOpen)renderNotifList();}\nfunction renderNotifList(){\n  const el=document.getElementById('np-list');\n  const hdr=`<div style=\"padding:8px;border-bottom:1px solid var(--border)\"><button class=\"btn-outline btn-sm\" onclick=\"testLocalNotif()\" style=\"width:100%;margin-bottom:6px\">\u901a\u77e5\u30c6\u30b9\u30c8(\u30ed\u30fc\u30ab\u30eb)</button><button class=\"btn-accent btn-sm\" onclick=\"runServerCheck()\" style=\"width:100%;margin-bottom:6px\">\u30b5\u30fc\u30d0\u30fc\u30c1\u30a7\u30c3\u30af\u5b9f\u884c</button><div id=\"server-check-result\" style=\"font-size:10px;color:var(--muted);line-height:1.6;margin-bottom:6px\"></div><div id=\"push-debug\" style=\"font-size:10px;color:var(--muted);line-height:1.6;word-break:break-all\"></div></div>`;\n  if(!notifs.length){el.innerHTML=hdr+'<div class=\"empty\" style=\"padding:16px\">\u901a\u77e5\u306f\u3042\u308a\u307e\u305b\u3093</div>';updatePushDebug();return;}\n  el.innerHTML=hdr+notifs.map(n=>`<div class=\"notif-item\"><div class=\"ni-title\">${esc(n.title)}</div><div class=\"ni-body\">${esc(n.body)}</div>${n.url?`<a class=\"ni-link\" href=\"${n.url}\" target=\"_blank\">\u25b6 \u958b\u304f</a>`:''}<div class=\"ni-time\">${fmtTime(n.time)}</div></div>`).join('');\n  updatePushDebug();\n}\nfunction clearNotifs(){notifs=[];localStorage.setItem('yt_notifs','[]');updateNotifBadge();renderNotifList();}\nfunction updateNotifBadge(){document.getElementById('notif-badge').textContent=notifs.length+'\u4ef6';document.getElementById('notif-badge').className=notifs.length?'badge warn':'badge off';}\nnavigator.serviceWorker?.addEventListener('message',e=>{\n  if(e.data?.type==='push'){notifs.unshift({...e.data,time:new Date().toISOString()});if(notifs.length>50)notifs=notifs.slice(0,50);localStorage.setItem('yt_notifs',JSON.stringify(notifs));updateNotifBadge();if(notifOpen)renderNotifList();}\n});\n\n// \u2500\u2500 Helpers \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction closeModal(id){document.getElementById(id).classList.remove('open');}\nconst esc=s=>String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\"/g,'&quot;');\nconst fmtTime=ts=>{const d=new Date(ts);return`${d.getMonth()+1}/${d.getDate()} ${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;};\nfunction urlB64ToUint8(b){const pad='='.repeat((4-b.length%4)%4);const raw=atob((b+pad).replace(/-/g,'+').replace(/_/g,'/'));return Uint8Array.from([...raw].map(c=>c.charCodeAt(0)));}\n</script>\n</body>\n</html>\n";

const PLAYER_HTML = "<!DOCTYPE html>\n<html lang=\"ja\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1,user-scalable=no\">\n<meta name=\"theme-color\" content=\"#000\">\n<title>Player</title>\n<style>\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent;user-select:none;-webkit-user-select:none}\nhtml,body{height:100%;background:#000;color:#fff;font-family:'Space Mono',monospace;overflow:hidden;touch-action:manipulation}\n#wrap{position:relative;width:100%;height:100%;display:flex;align-items:center;justify-content:center;background:#000}\nvideo{width:100%;height:100%;object-fit:contain;display:block}\n/* controls overlay */\n#ctrl{position:absolute;inset:0;display:flex;flex-direction:column;justify-content:space-between;transition:opacity .25s}\n#ctrl.hidden{opacity:0;pointer-events:none}\n#top{display:flex;align-items:center;gap:10px;padding:14px 14px 20px;background:linear-gradient(rgba(0,0,0,.7),transparent)}\n#back{background:none;border:none;color:#fff;font-size:22px;cursor:pointer;padding:2px 8px;line-height:1}\n#ttl{flex:1;font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:#ddd}\n#author{font-size:10px;color:#999}\n#bot{padding:6px 14px 20px;background:linear-gradient(transparent,rgba(0,0,0,.8))}\n/* seek */\n#seek-wrap{position:relative;height:22px;display:flex;align-items:center;margin-bottom:4px;cursor:pointer;touch-action:none}\n#seek-bg{position:absolute;height:3px;width:100%;background:rgba(255,255,255,.2);border-radius:2px}\n#seek-buf{position:absolute;height:3px;background:rgba(255,255,255,.35);border-radius:2px;width:0}\n#seek-fill{position:absolute;height:3px;background:#7fffb2;border-radius:2px;width:0;transition:width .1s}\n#seek-thumb{position:absolute;width:14px;height:14px;background:#7fffb2;border-radius:50%;transform:translateX(-50%);left:0;top:50%;margin-top:-7px}\n/* row */\n#row{display:flex;align-items:center;gap:8px}\n.ibtn{background:none;border:none;color:#fff;cursor:pointer;padding:6px;font-size:20px;line-height:1;border-radius:50%}\n.ibtn:active{background:rgba(255,255,255,.15)}\n.ibtn svg{width:20px;height:20px;fill:#fff;display:block}\n#time{font-size:11px;color:#bbb;white-space:nowrap}\n.sp{flex:1}\n/* quality menu */\n#qmenu{position:absolute;bottom:72px;right:14px;background:#111;border:1px solid #2a2a2a;border-radius:8px;overflow:hidden;display:none;z-index:20;min-width:90px}\n#qmenu.open{display:block}\n#qmenu button{display:block;width:100%;padding:9px 18px;background:none;border:none;color:#ccc;font-size:12px;font-family:inherit;cursor:pointer;text-align:left;white-space:nowrap}\n#qmenu button:active,#qmenu button.sel{background:#1e1e1e;color:#7fffb2}\n/* center overlays */\n#center{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);pointer-events:none;display:flex;flex-direction:column;align-items:center;gap:10px}\n#play-icon{width:60px;height:60px;background:rgba(0,0,0,.6);border-radius:50%;display:flex;align-items:center;justify-content:center;opacity:0;transition:opacity .2s}\n#play-icon.show{opacity:1}\n#speed-badge{background:rgba(0,0,0,.7);color:#7fffb2;padding:6px 18px;border-radius:20px;font-size:13px;opacity:0;transition:opacity .2s}\n#speed-badge.show{opacity:1}\n#spinner{width:36px;height:36px;border:3px solid rgba(255,255,255,.15);border-top-color:#7fffb2;border-radius:50%;animation:spin 1s linear infinite;display:none}\n@keyframes spin{to{transform:rotate(360deg)}}\n#err{background:rgba(200,50,50,.85);padding:10px 18px;border-radius:8px;font-size:12px;display:none;text-align:center;max-width:280px}\n/* tap zone */\n#tap{position:absolute;top:56px;left:0;right:0;bottom:72px}\n</style>\n</head>\n<body>\n\n<div id=\"wrap\">\n  <video id=\"v\" playsinline preload=\"auto\"></video>\n\n  <div id=\"center\">\n    <div id=\"spinner\"></div>\n    <div id=\"play-icon\">\n      <svg viewBox=\"0 0 24 24\" width=\"28\" height=\"28\" fill=\"#fff\"><path d=\"M8 5v14l11-7z\"/></svg>\n    </div>\n    <div id=\"speed-badge\"></div>\n    <div id=\"err\"></div>\n  </div>\n\n  <div id=\"tap\"></div>\n\n  <div id=\"ctrl\">\n    <div id=\"top\">\n      <button id=\"back\">&#8592;</button>\n      <div>\n        <div id=\"ttl\"></div>\n        <div id=\"author\"></div>\n      </div>\n    </div>\n    <div id=\"bot\">\n      <div id=\"seek-wrap\">\n        <div id=\"seek-bg\"></div>\n        <div id=\"seek-buf\"></div>\n        <div id=\"seek-fill\"></div>\n        <div id=\"seek-thumb\"></div>\n      </div>\n      <div id=\"row\">\n        <button class=\"ibtn\" id=\"play-btn\">\n          <svg id=\"play-svg\" viewBox=\"0 0 24 24\"><path d=\"M8 5v14l11-7z\"/></svg>\n        </button>\n        <span id=\"time\">0:00 / 0:00</span>\n        <div class=\"sp\"></div>\n        <button class=\"ibtn\" id=\"q-btn\" title=\"\u753b\u8cea\">\n          <svg viewBox=\"0 0 24 24\"><path d=\"M19.14 12.94c.04-.3.06-.61.06-.94s-.02-.64-.07-.94l2.03-1.58a.49.49 0 0 0 .12-.61l-1.92-3.32a.488.488 0 0 0-.59-.22l-2.39.96a7.01 7.01 0 0 0-1.62-.94l-.36-2.54a.484.484 0 0 0-.48-.41h-3.84c-.24 0-.43.17-.47.41l-.36 2.54c-.59.24-1.13.57-1.62.94l-2.39-.96c-.22-.08-.47 0-.59.22L2.74 8.87c-.12.21-.08.47.12.61l2.03 1.58c-.05.3-.07.62-.07.94s.02.64.07.94l-2.03 1.58a.49.49 0 0 0-.12.61l1.92 3.32c.12.22.37.29.59.22l2.39-.96c.5.37 1.04.7 1.62.94l.36 2.54c.05.24.24.41.48.41h3.84c.24 0 .44-.17.47-.41l.36-2.54c.59-.24 1.13-.57 1.62-.94l2.39.96c.22.08.47 0 .59-.22l1.92-3.32c.12-.22.07-.47-.12-.61l-2.01-1.58zM12 15.6c-1.98 0-3.6-1.62-3.6-3.6s1.62-3.6 3.6-3.6 3.6 1.62 3.6 3.6-1.62 3.6-3.6 3.6z\"/></svg>\n        </button>\n        <button class=\"ibtn\" id=\"fs-btn\" title=\"\u5168\u753b\u9762\">\n          <svg id=\"fs-svg\" viewBox=\"0 0 24 24\"><path d=\"M7 14H5v5h5v-2H7v-3zm-2-4h2V7h3V5H5v5zm12 7h-3v2h5v-5h-2v3zM14 5v2h3v3h2V5h-5z\"/></svg>\n        </button>\n      </div>\n    </div>\n  </div>\n\n  <div id=\"qmenu\"></div>\n</div>\n\n<script>\nconst WORKER = 'https://yt-push-register.a6068376.workers.dev';\nconst params = new URLSearchParams(location.search);\nconst videoId = params.get('v') || '';\nconst initTitle = decodeURIComponent(params.get('t') || '');\n\nconst v = document.getElementById('v');\nlet streams = [], curStreamIdx = 0;\nlet ctrlTimer, ctrlVisible = true;\nlet longTimer, isLong = false, isSeeking = false;\n\ndocument.getElementById('ttl').textContent = initTitle;\ndocument.getElementById('back').onclick = () => history.back();\n\n// Load stream info\n(async () => {\n  showSpinner(true);\n  try {\n    const res = await fetch(`${WORKER}/stream?v=${videoId}`);\n    const data = await res.json();\n    if (data.error) throw new Error(data.error);\n    streams = data.streams;\n    document.getElementById('ttl').textContent = data.title || initTitle;\n    document.getElementById('author').textContent = data.author || '';\n    buildQMenu();\n    playStream(0);\n  } catch(e) {\n    showErr(e.message);\n  } finally {\n    showSpinner(false);\n  }\n})();\n\nfunction playStream(idx) {\n  if (!streams[idx]) return;\n  curStreamIdx = idx;\n  const t = v.currentTime;\n  v.src = streams[idx].url;\n  v.load();\n  v.currentTime = t;\n  v.play().catch(() => {});\n  document.querySelectorAll('#qmenu button').forEach((b, i) => b.classList.toggle('sel', i === idx));\n}\n\nfunction buildQMenu() {\n  const m = document.getElementById('qmenu');\n  m.innerHTML = streams.map((s, i) =>\n    `<button onclick=\"playStream(${i})\">${s.quality}</button>`\n  ).join('');\n}\n\n// Video events\nv.addEventListener('waiting', () => showSpinner(true));\nv.addEventListener('playing', () => showSpinner(false));\nv.addEventListener('canplay', () => showSpinner(false));\nv.addEventListener('timeupdate', tickSeek);\nv.addEventListener('progress', tickBuf);\nv.addEventListener('ended', () => updatePlayBtn(false));\nv.addEventListener('play', () => updatePlayBtn(true));\nv.addEventListener('pause', () => updatePlayBtn(false));\n\nfunction tickSeek() {\n  if (isSeeking) return;\n  const pct = v.duration ? (v.currentTime / v.duration) * 100 : 0;\n  document.getElementById('seek-fill').style.width = pct + '%';\n  document.getElementById('seek-fill').style.transition = 'none';\n  document.getElementById('seek-thumb').style.left = pct + '%';\n  document.getElementById('time').textContent = fmt(v.currentTime) + ' / ' + fmt(v.duration);\n}\n\nfunction tickBuf() {\n  if (!v.duration) return;\n  try {\n    const buf = v.buffered.length ? (v.buffered.end(v.buffered.length - 1) / v.duration) * 100 : 0;\n    document.getElementById('seek-buf').style.width = buf + '%';\n  } catch {}\n}\n\nfunction fmt(s) {\n  s = Math.floor(s || 0);\n  return Math.floor(s / 60) + ':' + (s % 60 < 10 ? '0' : '') + (s % 60);\n}\n\nfunction updatePlayBtn(playing) {\n  document.getElementById('play-svg').innerHTML = playing\n    ? '<path d=\"M6 19h4V5H6v14zm8-14v14h4V5h-4z\"/>'\n    : '<path d=\"M8 5v14l11-7z\"/>';\n}\n\n// Play/pause button\ndocument.getElementById('play-btn').onclick = () => {\n  v.paused ? v.play() : v.pause();\n  showCtrl();\n};\n\n// Tap zone \u2014 tap = play/pause, longpress = 2x\nconst tap = document.getElementById('tap');\ntap.addEventListener('click', () => {\n  if (isLong) return;\n  v.paused ? v.play() : v.pause();\n  flashPlayIcon();\n  showCtrl();\n});\ntap.addEventListener('touchstart', e => {\n  isLong = false;\n  longTimer = setTimeout(() => {\n    isLong = true;\n    v.playbackRate = 2;\n    showBadge('2x');\n  }, 500);\n}, { passive: true });\ntap.addEventListener('touchend', () => {\n  clearTimeout(longTimer);\n  if (isLong) {\n    v.playbackRate = 1;\n    showBadge('1x', 600);\n  }\n  isLong = false;\n});\ntap.addEventListener('touchmove', () => clearTimeout(longTimer), { passive: true });\n\nfunction flashPlayIcon() {\n  const el = document.getElementById('play-icon');\n  el.querySelector('path').setAttribute('d', v.paused\n    ? 'M8 5v14l11-7z'\n    : 'M6 19h4V5H6v14zm8-14v14h4V5h-4z');\n  el.classList.add('show');\n  setTimeout(() => el.classList.remove('show'), 600);\n}\n\nfunction showBadge(txt, dur = 99999) {\n  const b = document.getElementById('speed-badge');\n  b.textContent = txt; b.classList.add('show');\n  if (dur < 99999) setTimeout(() => b.classList.remove('show'), dur);\n}\n\n// Seek bar\nconst sw = document.getElementById('seek-wrap');\nfunction seekAt(clientX) {\n  const r = sw.getBoundingClientRect();\n  const pct = Math.max(0, Math.min((clientX - r.left) / r.width, 1));\n  document.getElementById('seek-fill').style.width = (pct * 100) + '%';\n  document.getElementById('seek-thumb').style.left = (pct * 100) + '%';\n  v.currentTime = pct * (v.duration || 0);\n}\nsw.addEventListener('touchstart', e => { isSeeking = true; seekAt(e.touches[0].clientX); e.stopPropagation(); }, { passive: true });\nsw.addEventListener('touchmove', e => { if (isSeeking) seekAt(e.touches[0].clientX); e.stopPropagation(); }, { passive: true });\nsw.addEventListener('touchend', e => { isSeeking = false; e.stopPropagation(); }, { passive: true });\nsw.addEventListener('mousedown', e => { isSeeking = true; seekAt(e.clientX); });\nwindow.addEventListener('mousemove', e => { if (isSeeking) seekAt(e.clientX); });\nwindow.addEventListener('mouseup', () => { isSeeking = false; });\n\n// Quality menu\ndocument.getElementById('q-btn').onclick = e => {\n  e.stopPropagation();\n  document.getElementById('qmenu').classList.toggle('open');\n  showCtrl();\n};\ndocument.getElementById('wrap').addEventListener('click', () => {\n  document.getElementById('qmenu').classList.remove('open');\n});\n\n// Fullscreen + auto landscape\ndocument.getElementById('fs-btn').onclick = async () => {\n  if (!document.fullscreenElement) {\n    await document.documentElement.requestFullscreen({ navigationUI: 'hide' }).catch(() => {});\n    await screen.orientation?.lock('landscape').catch(() => {});\n  } else {\n    await document.exitFullscreen().catch(() => {});\n    await screen.orientation?.unlock();\n  }\n};\ndocument.addEventListener('fullscreenchange', () => {\n  const in_fs = !!document.fullscreenElement;\n  document.getElementById('fs-svg').innerHTML = in_fs\n    ? '<path d=\"M5 16h3v3h2v-5H5v2zm3-8H5v2h5V5H8v3zm6 11h2v-3h3v-2h-5v5zm2-11V5h-2v5h5V8h-3z\"/>'\n    : '<path d=\"M7 14H5v5h5v-2H7v-3zm-2-4h2V7h3V5H5v5zm12 7h-3v2h5v-5h-2v3zM14 5v2h3v3h2V5h-5z\"/>';\n});\n\n// Controls visibility\nfunction showCtrl() {\n  document.getElementById('ctrl').classList.remove('hidden');\n  ctrlVisible = true;\n  clearTimeout(ctrlTimer);\n  ctrlTimer = setTimeout(() => {\n    document.getElementById('ctrl').classList.add('hidden');\n    ctrlVisible = false;\n  }, 3000);\n}\ndocument.getElementById('ctrl').addEventListener('click', showCtrl);\nshowCtrl();\n\nfunction showSpinner(on) { document.getElementById('spinner').style.display = on ? 'block' : 'none'; }\nfunction showErr(msg) {\n  const e = document.getElementById('err');\n  e.textContent = '\u30a8\u30e9\u30fc: ' + msg; e.style.display = 'block';\n}\n\n// Prevent context menu\ndocument.addEventListener('contextmenu', e => e.preventDefault());\n</script>\n</body>\n</html>\n";

const SW_JS = "const CACHE = 'yt-watcher-v2';\n\nself.addEventListener('install', e => {\n  e.waitUntil(caches.open(CACHE).then(c => c.addAll(['/yt-watcher/'])));\n  self.skipWaiting();\n});\n\nself.addEventListener('activate', e => {\n  e.waitUntil(caches.keys().then(keys =>\n    Promise.all(keys.filter(k => k !== CACHE).map(k => caches.delete(k)))\n  ));\n  self.clients.claim();\n});\n\nself.addEventListener('fetch', e => {\n  if (e.request.method !== 'GET') return;\n  e.respondWith(\n    fetch(e.request).then(r => {\n      const c = r.clone();\n      caches.open(CACHE).then(ca => ca.put(e.request, c));\n      return r;\n    }).catch(() => caches.match(e.request))\n  );\n});\n\nself.addEventListener('push', e => {\n  let data = {};\n  try { data = e.data.json(); } catch {}\n  const title = data.title || 'YT Watcher';\n  const body  = data.body  || '';\n  const url   = data.url   || '/yt-watcher/';\n  e.waitUntil(Promise.all([\n    self.registration.showNotification(title, {\n      body,\n      tag:  'yt-watcher',\n      data: { url }\n    }),\n    self.clients.matchAll({ type: 'window' }).then(clients => {\n      for (const c of clients) c.postMessage({ type: 'push', title, body, url });\n    })\n  ]));\n});\n\nself.addEventListener('notificationclick', e => {\n  e.notification.close();\n  const url = e.notification.data?.url || '/yt-watcher/';\n  e.waitUntil(clients.openWindow(url));\n});\n";

