function injectConfig(html, env) {
  const cfg = JSON.stringify({ worker: '', vapid: env.VAPID_PUBLIC || '' });
  return html.replace('</head>', '<script>window.__CFG=' + cfg + ';<\/script></head>');
}

const CORS = {
  'Access-Control-Allow-Origin':  '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type',
};

function genCode(len) {
  len = len || 6;
  const chars = 'abcdefghjkmnpqrstuvwxyz23456789';
  let s = '';
  for (let i = 0; i < len; i++) s += chars[Math.floor(Math.random() * chars.length)];
  return s;
}

// ── KV helpers ───────────────────────────────────────────────────────────────
async function getKVArray(env, key) {
  try {
    const raw = await env.KV_BINDING.get(key);
    if (!raw) return [];
    const v = JSON.parse(raw);
    return Array.isArray(v) ? v : [];
  } catch { return []; }
}
async function getKVObject(env, key) {
  try {
    const raw = await env.KV_BINDING.get(key);
    if (!raw) return {};
    const v = JSON.parse(raw);
    return (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};
  } catch { return {}; }
}

// ── base64url helpers ───────────────────────────────────────────────────────
function b64urlToBytes(str) {
  str = str.replace(/-/g, '+').replace(/_/g, '/');
  while (str.length % 4) str += '=';
  const bin = atob(str);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}
function bytesToB64url(bytes) {
  let bin = '';
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  return btoa(bin).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}
function concatBytes() {
  let total = 0;
  for (const a of arguments) total += a.length;
  const out = new Uint8Array(total);
  let off = 0;
  for (const a of arguments) { out.set(a, off); off += a.length; }
  return out;
}

// ── VAPID JWT (ES256) — RFC 8292 ───────────────────────────────────────────────
async function createVapidJWT(audience, subject, privateKeyB64url) {
  const enc = new TextEncoder();
  const header  = bytesToB64url(enc.encode(JSON.stringify({ typ: 'JWT', alg: 'ES256' })));
  const payload = bytesToB64url(enc.encode(JSON.stringify({
    aud: audience,
    exp: Math.floor(Date.now() / 1000) + 12 * 3600,
    sub: subject,
  })));
  const unsigned = header + '.' + payload;
  const keyBytes = b64urlToBytes(privateKeyB64url);
  const privateKey = await crypto.subtle.importKey(
    'pkcs8', keyBytes, { name: 'ECDSA', namedCurve: 'P-256' }, false, ['sign']
  );
  const sig = new Uint8Array(await crypto.subtle.sign(
    { name: 'ECDSA', hash: 'SHA-256' }, privateKey, enc.encode(unsigned)
  ));
  return unsigned + '.' + bytesToB64url(sig);
}

// ── Web Push payload encryption — RFC 8291 (aes128gcm) ─────────────────────────
async function encryptPushPayload(payloadStr, p256dhB64, authB64) {
  const enc = new TextEncoder();
  const plaintext  = enc.encode(payloadStr);
  const uaPublic   = b64urlToBytes(p256dhB64);
  const authSecret = b64urlToBytes(authB64);

  const asKeyPair  = await crypto.subtle.generateKey({ name: 'ECDH', namedCurve: 'P-256' }, true, ['deriveBits']);
  const asPublicRaw = new Uint8Array(await crypto.subtle.exportKey('raw', asKeyPair.publicKey));
  const uaPublicKey = await crypto.subtle.importKey('raw', uaPublic, { name: 'ECDH', namedCurve: 'P-256' }, false, []);
  const sharedSecret = new Uint8Array(await crypto.subtle.deriveBits(
    { name: 'ECDH', public: uaPublicKey }, asKeyPair.privateKey, 256
  ));

  const salt = crypto.getRandomValues(new Uint8Array(16));

  // PRK = HKDF-Extract(auth_secret, ecdh_secret); ikm = HKDF-Expand(PRK, info, 32)
  const ikmInfo = concatBytes(enc.encode('WebPush: info'), new Uint8Array([0]), uaPublic, asPublicRaw);
  const secretKey = await crypto.subtle.importKey('raw', sharedSecret, 'HKDF', false, ['deriveBits']);
  const ikm = new Uint8Array(await crypto.subtle.deriveBits(
    { name: 'HKDF', hash: 'SHA-256', salt: authSecret, info: ikmInfo }, secretKey, 256
  ));

  const ikmKey = await crypto.subtle.importKey('raw', ikm, 'HKDF', false, ['deriveBits']);
  const cekInfo   = concatBytes(enc.encode('Content-Encoding: aes128gcm'), new Uint8Array([0]));
  const nonceInfo = concatBytes(enc.encode('Content-Encoding: nonce'), new Uint8Array([0]));
  const cek = new Uint8Array(await crypto.subtle.deriveBits(
    { name: 'HKDF', hash: 'SHA-256', salt, info: cekInfo }, ikmKey, 128
  ));
  const nonce = new Uint8Array(await crypto.subtle.deriveBits(
    { name: 'HKDF', hash: 'SHA-256', salt, info: nonceInfo }, ikmKey, 96
  ));

  // padding delimiter (0x02 = last record, no further padding)
  const padded = concatBytes(plaintext, new Uint8Array([2]));
  const cekKey = await crypto.subtle.importKey('raw', cek, 'AES-GCM', false, ['encrypt']);
  const ciphertext = new Uint8Array(await crypto.subtle.encrypt({ name: 'AES-GCM', iv: nonce }, cekKey, padded));

  const rs = 4096;
  const rsBytes = new Uint8Array(4);
  new DataView(rsBytes.buffer).setUint32(0, rs, false);

  const header = concatBytes(salt, rsBytes, new Uint8Array([asPublicRaw.length]), asPublicRaw);
  return concatBytes(header, ciphertext);
}

// ── Send a single Web Push ──────────────────────────────────────────────────
async function sendWebPush(env, sub, payloadObj) {
  const endpoint = sub.endpoint;
  const audience = new URL(endpoint).origin;
  const subject  = env.VAPID_EMAIL || 'mailto:push@example.com';
  const jwt  = await createVapidJWT(audience, subject, env.VAPID_PRIVATE);
  const body = await encryptPushPayload(JSON.stringify(payloadObj), sub.keys.p256dh, sub.keys.auth);
  return fetch(endpoint, {
    method: 'POST',
    headers: {
      'Content-Type':     'application/octet-stream',
      'Content-Encoding': 'aes128gcm',
      'TTL':              '86400',
      'Authorization':    'vapid t=' + jwt + ', k=' + env.VAPID_PUBLIC,
    },
    body,
  });
}

// Send to all subscriptions; prune expired (404/410) from KV
async function pushToAll(env, subs, payload) {
  let changed = false;
  const kept = [];
  for (const sub of subs) {
    try {
      const res = await sendWebPush(env, sub, payload);
      if (res.status === 404 || res.status === 410) { changed = true; continue; }
      kept.push(sub);
    } catch (e) {
      kept.push(sub); // network error — keep, don't drop
    }
  }
  if (changed) {
    subs.length = 0;
    subs.push.apply(subs, kept);
    await env.KV_BINDING.put('push_subscriptions', JSON.stringify(kept));
  }
}

// ── Playlist fetch ─────────────────────────────────────────────────────────────
async function fetchPlaylistVideos(playlistId, apiKey) {
  const videos = []; let pageToken = '';
  do {
    const u = 'https://www.googleapis.com/youtube/v3/playlistItems?part=snippet&maxResults=50&playlistId=' + playlistId + '&key=' + apiKey + (pageToken ? '&pageToken=' + pageToken : '');
    const r = await fetch(u);
    if (!r.ok) throw new Error('YouTube API: ' + r.status);
    const data = await r.json();
    if (data.error) throw new Error(data.error.message);
    for (const item of (data.items || [])) {
      const s = item.snippet;
      if (!s || !s.resourceId || !s.resourceId.videoId) continue;
      if (s.title === 'Deleted video' || s.title === 'Private video') continue;
      videos.push({ id: s.resourceId.videoId, title: s.title, thumb: (s.thumbnails && (s.thumbnails.medium || s.thumbnails.default) || {}).url || '' });
    }
    pageToken = data.nextPageToken || '';
  } while (pageToken);
  return videos;
}

// ── Main check: playlists + schedule notifications ─────────────────────────────
async function runCheck(env) {
  const subs      = await getKVArray(env, 'push_subscriptions');
  const playlists = await getKVArray(env, 'playlists');
  const schedules = await getKVArray(env, 'schedules');
  const state       = await getKVObject(env, 'yt_state');
  const stateBefore = JSON.stringify(state);

  const report = { playlists: [], scheduleSent: 0, subscribers: subs.length, errors: [] };

  for (const pl of playlists) {
    const plId = pl.id, plTitle = pl.title || plId;
    if (!plId) continue;
    try {
      const videos = await fetchPlaylistVideos(plId, env.YT_API_KEY);
      const known = new Set(state[plId] || []);
      const newVideos = videos.filter(v => !known.has(v.id));
      state[plId] = videos.map(v => v.id);

      if (newVideos.length && subs.length) {
        for (const v of newVideos.slice(0, 3)) {
          await pushToAll(env, subs, { title: '新着: ' + plTitle, body: v.title, url: 'https://www.youtube.com/watch?v=' + v.id });
        }
        if (newVideos.length > 3) {
          await pushToAll(env, subs, { title: plTitle + ': 他' + (newVideos.length - 3) + '件の新着', body: 'タップして確認', url: 'https://www.youtube.com/playlist?list=' + plId });
        }
      }
      report.playlists.push({ title: plTitle, total: videos.length, new: newVideos.length });
    } catch (e) {
      report.errors.push(plTitle + ': ' + e.message);
    }
  }

  // ── Schedule notifications (JST) ─────────────────────────────────────────────
  const sentLog = await getKVObject(env, 'sent_notifications');
  const sentBefore = JSON.stringify(sentLog);

  const jstNow = new Date(Date.now() + 9 * 3600 * 1000);
  const today  = jstNow.toISOString().slice(0, 10);
  const nowMin = jstNow.getUTCHours() * 60 + jstNow.getUTCMinutes();

  for (const ev of schedules) {
    if (!ev.notify || ev.date !== today || !ev.startTime) continue;
    const parts = ev.startTime.split(':');
    const startMin = parseInt(parts[0], 10) * 60 + parseInt(parts[1], 10);
    const notifyBefore = ev.notifyBefore && ev.notifyBefore.length ? ev.notifyBefore : [60, 30, 10];
    for (const nb of notifyBefore) {
      const triggerMin = startMin - nb;
      const key = today + ':' + ev.eventId + ':' + nb;
      if (nowMin >= triggerMin && !sentLog[key]) {
        await pushToAll(env, subs, {
          title: 'まもなく開始: ' + (ev.subject || ''),
          body:  (ev.unit || '') + '  ' + ev.startTime + '開始  ' + nb + '分前',
          url:   (ev.link && ev.link.url) || ev.zoomUrl || '',
        });
        sentLog[key] = true;
        report.scheduleSent++;
      }
    }
  }
  // prune old keys (keep only today's)
  for (const k of Object.keys(sentLog)) if (!k.startsWith(today)) delete sentLog[k];

  // Write back only if changed (keep KV writes minimal)
  if (JSON.stringify(state)   !== stateBefore) await env.KV_BINDING.put('yt_state', JSON.stringify(state));
  if (JSON.stringify(sentLog) !== sentBefore)  await env.KV_BINDING.put('sent_notifications', JSON.stringify(sentLog));

  return report;
}

// ── HTTP handlers ──────────────────────────────────────────────────────────────
function htmlRes(content) {
  return new Response(content, { headers: { 'Content-Type': 'text/html; charset=utf-8', 'Cache-Control': 'no-cache' } });
}
function apiJson(data, status) {
  return new Response(JSON.stringify(data), { status: status || 200, headers: Object.assign({}, CORS, { 'Content-Type': 'application/json' }) });
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const method = request.method;

    if (method === 'OPTIONS') return new Response(null, { headers: CORS });

    if (method === 'GET') {
      const p = url.pathname;

      if (p === '/' || p === '/index.html') return htmlRes(injectConfig(INDEX_HTML, env));
      if (p === '/player.html') return htmlRes(PLAYER_HTML);
      if (p === '/sw.js') return new Response(SW_JS, { headers: { 'Content-Type': 'application/javascript; charset=utf-8', 'Service-Worker-Allowed': '/', 'Cache-Control': 'no-cache' } });
      if (p === '/manifest.json') return new Response(MANIFEST_JSON, { headers: { 'Content-Type': 'application/manifest+json; charset=utf-8' } });

      if (p === '/videos') {
        const plId = url.searchParams.get('playlistId');
        if (!plId) return apiJson({ error: 'Missing playlistId' }, 400);
        try { return apiJson(await fetchPlaylistVideos(plId, env.YT_API_KEY)); }
        catch (e) { return apiJson({ error: e.message }, 500); }
      }

      if (p === '/share') {
        const code = url.searchParams.get('code');
        if (!code) return apiJson({ error: 'Missing code' }, 400);
        try {
          const raw = await env.KV_BINDING.get('share:' + code);
          if (!raw) return apiJson({ error: 'Not found or expired' }, 404);
          return apiJson({ data: JSON.parse(raw) });
        } catch (e) { return apiJson({ error: e.message }, 500); }
      }

      // Manual trigger / debug — runs the same logic as the cron
      if (p === '/run-check') {
        try { return apiJson(await runCheck(env)); }
        catch (e) { return apiJson({ error: e.message, stack: e.stack }, 500); }
      }

      if (p === '/subscriptions' || p === '/playlists' || p === '/schedules') {
        if (url.searchParams.get('secret') !== env.API_SECRET) return apiJson({ error: 'Unauthorized' }, 401);
        const key = p === '/subscriptions' ? 'push_subscriptions' : (p === '/playlists' ? 'playlists' : 'schedules');
        return apiJson(await getKVArray(env, key));
      }
    }

    if (method === 'POST' && url.pathname === '/share') {
      try {
        const { data } = await request.json();
        if (!data) return apiJson({ error: 'Missing data' }, 400);
        const code = genCode();
        await env.KV_BINDING.put('share:' + code, JSON.stringify(data), { expirationTtl: 86400 * 30 });
        return apiJson({ code, url: url.origin + '/?code=' + code });
      } catch (e) { return apiJson({ error: e.message }, 500); }
    }

    if (method === 'POST' && url.pathname === '/subscribe') {
      try {
        const { subscription } = await request.json();
        if (!subscription || !subscription.endpoint) return apiJson({ error: 'Missing subscription' }, 400);
        let subs = await getKVArray(env, 'push_subscriptions');
        subs = subs.filter(s => s.endpoint !== subscription.endpoint);
        subs.push(subscription);
        await env.KV_BINDING.put('push_subscriptions', JSON.stringify(subs));
        return apiJson({ ok: true, total: subs.length });
      } catch (e) { return apiJson({ error: e.message }, 500); }
    }

    if (method === 'POST' && url.pathname === '/unsubscribe') {
      try {
        const { endpoint } = await request.json();
        let subs = await getKVArray(env, 'push_subscriptions');
        subs = subs.filter(s => s.endpoint !== endpoint);
        await env.KV_BINDING.put('push_subscriptions', JSON.stringify(subs));
        return apiJson({ ok: true, total: subs.length });
      } catch (e) { return apiJson({ error: e.message }, 500); }
    }

    if (method === 'POST' && url.pathname === '/playlists') {
      try {
        const { playlists } = await request.json();
        if (!Array.isArray(playlists)) return apiJson({ error: 'invalid' }, 400);
        await env.KV_BINDING.put('playlists', JSON.stringify(playlists));
        return apiJson({ ok: true });
      } catch (e) { return apiJson({ error: e.message }, 500); }
    }

    if (method === 'POST' && url.pathname === '/schedules') {
      try {
        const { schedules } = await request.json();
        if (!Array.isArray(schedules)) return apiJson({ error: 'invalid' }, 400);
        await env.KV_BINDING.put('schedules', JSON.stringify(schedules));
        return apiJson({ ok: true, count: schedules.length });
      } catch (e) { return apiJson({ error: e.message }, 500); }
    }

    // Legacy combined endpoint
    if (method === 'POST' && (url.pathname === '/' || url.pathname === '/update-playlists')) {
      try {
        const body = await request.json();
        if (body.subscription) {
          let subs = await getKVArray(env, 'push_subscriptions');
          subs = subs.filter(s => s.endpoint !== body.subscription.endpoint);
          subs.push(body.subscription);
          await env.KV_BINDING.put('push_subscriptions', JSON.stringify(subs));
          return apiJson({ ok: true, total: subs.length });
        }
        if (body.playlists && Array.isArray(body.playlists)) {
          await env.KV_BINDING.put('playlists', JSON.stringify(body.playlists));
          return apiJson({ ok: true });
        }
        return apiJson({ error: 'unrecognized body' }, 400);
      } catch (e) { return apiJson({ error: e.message }, 500); }
    }

    return htmlRes(injectConfig(INDEX_HTML, env));
  },

  // ── Cloudflare Cron Trigger ────────────────────────────────────────────────
  async scheduled(event, env, ctx) {
    ctx.waitUntil(runCheck(env));
  },
};

